-- ----------------------------
-- Table structure for med_message
-- ----------------------------
DROP TABLE IF EXISTS `med_message`;
CREATE TABLE `med_message`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `conversation_id` bigint NOT NULL COMMENT '关联会话ID',
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '角色: user/assistant',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息内容(支持Markdown)',
  `sources` json NULL COMMENT '引用来源(文档名+章节+页码)',
  `retrieval_log` json NULL COMMENT '检索过程日志(用于可视化)',
  `feedback` tinyint NOT NULL DEFAULT 0 COMMENT '反馈: 1有用 -1无用 0未评',
  `is_fallback` tinyint NOT NULL DEFAULT 0 COMMENT '是否触发兜底回答',
  `tokens_used` int NULL DEFAULT NULL COMMENT 'Token消耗',
  `response_time` int NULL DEFAULT NULL COMMENT '响应时间(毫秒)',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_conversation_id`(`conversation_id` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 39 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '对话消息表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of med_message
-- ----------------------------
INSERT INTO `med_message` VALUES (1, 1, 'user', '被公司无故辞退，我有哪些法律权利？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 09:55:00');
INSERT INTO `med_message` VALUES (2, 1, 'assistant', '⚠️ 知识库未匹配到相关文献，以下为通用法律知识\n\n根据《劳动合同法》相关规定，**被无故辞退（违法解除劳动合同）**，您享有以下法律权利：\n\n## 一、要求继续履行劳动合同\n- 您可要求用人单位恢复劳动关系，继续履行合同\n- 适用于您仍有意愿继续在该单位工作的情形\n\n## 二、要求支付违法解除赔偿金\n- 赔偿金 = **经济补偿金 × 2倍**\n- 经济补偿金标准：每工作满1年支付1个月工资（不足半年按半年计，超过半年不足1年按1年计）\n- 月工资以劳动合同解除前12个月平均工资为准\n\n## 三、维权途径\n1. **协商调解**：与用人单位直接协商或申请劳动争议调解委员会调解\n2. **劳动仲裁**：向当地劳动争议仲裁委员会申请仲裁（**必经前置程序**，时效为1年）\n3. **诉讼**：对仲裁结果不服可向人民法院起诉\n\n## 四、注意事项\n- 及时收集证据：劳动合同、工资流水、解除通知书、工作记录等\n- 劳动仲裁申请时效为**知道或应当知道权利被侵害之日起1年**\n\n**建议咨询领域：劳动法律师**\n\n---\nℹ️ **说明**：当前知识库中未找到与您问题高度相关的法律文献，以上回答基于通用法律知识，仅供参考。\n**建议咨询专业律师**，以获取针对您具体情况的法律意见。', '[]', '{\"rrfCount\": 0, \"rerankTop\": 0, \"isFallback\": true, \"bm25Results\": 0, \"vectorResults\": 0, \"rewrittenQuery\": \"违法解除劳动合同赔偿金经济补偿金劳动权利\"}', 1, 0, NULL, NULL, '2026-03-21 09:58:00');
INSERT INTO `med_message` VALUES (3, 2, 'user', '离婚时房产应该如何分割？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 10:30:00');
INSERT INTO `med_message` VALUES (4, 2, 'assistant', '⚠️ 知识库未匹配到相关文献，以下为通用法律知识\n\n根据《民法典》婚姻家庭编相关规定，**离婚时房产分割**需区分不同情形：\n\n## 一、夫妻共同财产（一般平均分割）\n- **婚后共同购买**的房产，属夫妻共同财产，离婚时一般各得50%\n- 分割方式：一方取得房产所有权并给另一方**折价补偿**，或协商出售后**平分价款**\n\n## 二、个人财产（不参与分割）\n- **婚前个人购买**并登记在一方名下的房产，属个人财产\n- **婚后一方父母全额出资**购买并登记在其子女名下，视为个人财产\n- **婚后一方父母部分出资**购买，该部分出资视为对其子女的个人赠与\n\n## 三、特殊情形处理\n- **一方婚前贷款购房，婚后共同还贷**：房产归产权方所有，但共同还贷部分及增值由法院综合认定后予以补偿\n- **登记在双方名下**：原则上属于共同财产\n- **有子女的情形**：法院可能优先考虑有利于子女成长的分配方式\n\n## 四、维权建议\n1. 尽量协议离婚，自行协商分割方案\n2. 协商不成可诉讼离婚，由法院判决\n3. 提前查询房产登记信息，保存购房合同、还款记录等证据\n\n**建议咨询领域：婚姻家事律师**\n\n---\nℹ️ **说明**：当前知识库中未找到与您问题高度相关的法律文献，以上回答基于通用法律知识，仅供参考。\n**建议咨询专业律师**，以获取针对您具体情况的法律意见。', '[]', '{\"rrfCount\": 0, \"rerankTop\": 0, \"isFallback\": true, \"bm25Results\": 0, \"vectorResults\": 0, \"rewrittenQuery\": \"离婚房产分割夫妻共同财产个人财产认定\"}', 1, 0, NULL, NULL, '2026-03-21 10:35:00');
INSERT INTO `med_message` VALUES (5, 4, 'user', '被公司无故辞退，我有哪些法律权利？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 19:11:19');
INSERT INTO `med_message` VALUES (6, 4, 'assistant', '⚠️ 知识库未匹配到相关文献，以下为通用法律知识  \n\n被公司无故辞退（即用人单位无法定理由、未履行法定程序单方解除劳动合同），您依法享有以下主要权利：\n\n1. **主张违法解除赔偿金**  \n   根据《中华人民共和国劳动合同法》第48条、第87条：  \n   - 若劳动关系已实际解除，您可要求公司支付**赔偿金**＝经济补偿金 × 2；  \n   - 经济补偿金按工作年限计算：每满1年支付1个月工资；6个月以上不满1年按1年计；不满6个月支付0.5个月工资；  \n   - 月工资标准为解除前12个月平均工资（含奖金、津贴等货币性收入），高于当地社平工资3倍的，按3倍封顶，且补偿年限最高12年。\n\n2. **请求继续履行劳动合同**（如您希望返岗）  \n   依据《劳动合同法》第48条，您可选择要求公司继续履行合同，并补发违法解除期间的工资及社保待遇。但若劳动合同已不能继续履行（如岗位已撤销、信任关系彻底破裂等），仲裁/法院可能支持赔偿金而非恢复劳动关系。\n\n3. **追索欠付劳动报酬与社保**  \n   - 工资、加班费、未休年休假工资、提成、报销款等应得而未付的款项，可一并主张；  \n   - 公司未依法缴纳社保的，可向当地社保经办机构投诉补缴（注意：社保补缴属行政职责，一般不通过劳动仲裁直接裁决）。\n\n4. **程序性权利保障**  \n   - 公司解除劳动合同须有合法依据（如《劳动合同法》第39、40、41条），并履行通知工会、书面送达等程序；  \n   - 若未通知工会或未听取工会意见（用人单位有工会的情形），可能构成程序违法，亦属违法解除。\n\n✅ 建议行动步骤：  \n- 立即保存证据：劳动合同、工资流水、考勤记录、辞退通知（书面/微信/邮件等）、工作沟通记录、社保缴费凭证等；  \n- 在**离职之日起1年内**向用人单位所在地或劳动合同履行地的**劳动人事争议仲裁委员会**申请劳动仲裁（免费，是诉讼前置程序）；  \n- 如对仲裁裁决不服，可在收到裁决书之日起15日内向人民法院提起诉讼。\n\n📌 特别提示：所谓“无故辞退”需结合具体情形判断（如是否构成严重违纪、是否符合客观情况变化等），表面“无理由”未必等于法律意义上的“违法解除”。个案差异大，强烈建议携带完整证据材料咨询当地执业律师或拨打12348公共法律服务热线获取针对性指导。\n\n---\nℹ️ **说明**：当前知识库中未找到与您问题高度相关的法律文献，以上回答基于通用法律知识，仅供参考。\n**建议咨询专业律师**，以获取针对您具体情况的法律意见。', '[]', '{\"rrfCount\": 0, \"rerankTop\": 0, \"isFallback\": true, \"bm25Results\": 0, \"originalQuery\": \"被公司无故辞退，我有哪些法律权利？\", \"vectorResults\": 0, \"rewrittenQuery\": \"用人单位单方解除劳动合同的法定条件、程序及违法解除的法律后果；劳动者在劳动合同被违法解除情形下的救济途径、赔偿标准与维权程序\"}', 1, 0, NULL, NULL, '2026-03-21 19:11:37');
INSERT INTO `med_message` VALUES (7, 5, 'user', '房东不退押金，我有哪些维权途径？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 19:12:19');
INSERT INTO `med_message` VALUES (8, 5, 'assistant', '⚠️ 知识库未匹配到相关文献，以下为通用法律知识  \n\n房东拒不退还押金属于常见的房屋租赁合同纠纷。根据《中华人民共和国民法典》第七百零三条、第七百一十条及第五百零九条等规定，押金性质为担保承租人依约履行合同义务（如按时交租、妥善使用房屋、结清费用、恢复原状等）的金钱担保，**并非预付租金或违约金**。是否应退、退多少，需结合合同约定与实际履约情况综合判断。\n\n您可依法采取以下维权途径（由易到难、由低成本到高成本）：\n\n1. **协商沟通**  \n   - 书面（微信、短信、邮件等）明确要求退还押金，列明依据（如已结清水电燃气费、无结构性损坏、已按约交还钥匙等），保留全部证据（合同、付款凭证、交接记录、照片/视频、沟通记录）。\n\n2. **向人民调解委员会申请调解**  \n   - 可联系物业、社区或街道司法所，免费调解；达成调解协议后可申请司法确认，具有强制执行力。\n\n3. **向当地住房城乡建设部门（住建局/房管局）投诉**  \n   - 部分地区对租赁市场有监管职责，可对违规收取、扣押押金行为进行行政督促（但无直接裁决权）。\n\n4. **申请仲裁（仅限合同中明确约定仲裁条款时）**  \n   - 若租赁合同约定“因本合同引起的争议提交××仲裁委员会仲裁”，可依约申请仲裁（一裁终局，效率较高）。\n\n5. **向人民法院提起诉讼**  \n   - 这是最具强制力的救济方式。  \n     - 诉讼标的额≤各省上年度就业人员年平均工资50%的（通常约2万—3万元），适用**小额诉讼程序**，一审终审、30日内审结；  \n     - 起诉需准备：起诉状、身份证明、租赁合同、押金支付凭证、房屋交接证明、损失/扣款异议证据、催告记录等；  \n     - 可主张：返还押金本金 + 占用期间利息（LPR标准）+ 合理维权费用（如诉讼费、公告费，律师费依合同约定或法院酌定）。\n\n✅ 特别提醒：  \n- 租赁合同是核心依据，请务必核查是否约定押金退还条件、扣减情形、退还时限；  \n- 若房东以“房屋损坏”为由扣款，须举证损害系您造成且超出正常损耗（《民法典》第七百一十一条：“承租人未按照约定的方法或者未根据租赁物的性质使用租赁物，致使租赁物受到损失的，出租人可以解除合同并请求赔偿损失”），自然损耗（如墙面轻微泛黄、地板正常磨损）不得扣费；  \n- 切勿自行撬锁、强占房屋或毁损设施，否则可能反担违约/侵权责任。\n\n建议尽快固定证据，并优先尝试协商或调解；若协商无果且金额较大，及时咨询专业律师或向法院起诉。  \n（注：具体操作请结合所在地地方性法规及司法实践，如《北京市住房租赁条例》《上海市房屋租赁条例》等可能有细化规定。）\n\n如需，我可协助您起草《押金退还催告函》或《民事起诉状》模板。\n\n---\nℹ️ **说明**：当前知识库中未找到与您问题高度相关的法律文献，以上回答基于通用法律知识，仅供参考。\n**建议咨询专业律师**，以获取针对您具体情况的法律意见。', '[]', '{\"rrfCount\": 0, \"rerankTop\": 0, \"isFallback\": true, \"bm25Results\": 0, \"originalQuery\": \"房东不退押金，我有哪些维权途径？\", \"vectorResults\": 0, \"rewrittenQuery\": \"房屋租赁合同履行完毕后出租人拒不返还租赁保证金的法律救济途径\"}', 0, 0, NULL, NULL, '2026-03-21 19:12:37');
INSERT INTO `med_message` VALUES (9, 6, 'user', '离婚时房产应该如何分割？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 19:14:08');
INSERT INTO `med_message` VALUES (10, 6, 'assistant', '⚠️ 知识库未匹配到相关文献，以下为通用法律知识  \n\n离婚时房产的分割需结合产权取得时间、出资情况、登记状态及是否存在特别约定等因素，依据《中华人民共和国民法典》第1062条（夫妻共同财产）、第1063条（个人财产）及第1087条（离婚时财产分割原则）综合判断。常见情形包括：\n\n1. **婚内购买、登记在一方或双方名下**：原则上属于夫妻共同财产，离婚时一般均等分割；但若一方能证明全部购房款来源于其个人财产（如婚前存款全额支付且资金流向清晰），可主张为个人财产。\n\n2. **婚前一方全款购房、登记在出资方名下**：属个人财产，不参与分割；若婚后加名，视为赠与，通常转化为共同财产，可协商或按出资及贡献比例分割。\n\n3. **婚前首付+婚后共同还贷**：房产一般认定为登记方个人财产，但婚后共同还贷及对应增值部分属于共同财产，另一方有权就还贷本息及增值部分享有补偿（计算公式参见最高人民法院关于适用《民法典》婚姻家庭编的解释（一）第78条）。\n\n4. **父母出资购房**：  \n　- 婚前出资：明确表示赠与一方的，属该方个人财产；未明确的，实践中多推定为对子女一方的赠与。  \n　- 婚后出资：无明确约定的，一般视为对夫妻双方的赠与（《民法典婚姻家庭编解释（一）》第29条）；若签署书面赠与协议或转账备注“赠与儿子/女儿个人”，可主张为个人财产。\n\n5. **农村宅基地房、小产权房、尚未取得产权证的预售房**：因权属受限，法院通常不予分割所有权，仅处理居住使用权、合同权益或另案处理。\n\n✅ 重要提示：  \n- 夫妻可自行签订书面《婚内财产协议》或《离婚协议》约定房产归属，该约定优先于法定分割规则；  \n- 涉及贷款未结清、产权受限、共有权人（如父母）等情况，分割可能受行政限制或需第三方同意；  \n- 实务中证据（如付款凭证、银行流水、聊天记录、公证文书等）对认定出资性质和真实意思至关重要。\n\n建议：房产分割常涉及复杂事实认定与证据组织，强烈建议咨询专业婚姻家事律师，结合具体材料制定维权策略。\n\n---\nℹ️ **说明**：当前知识库中未找到与您问题高度相关的法律文献，以上回答基于通用法律知识，仅供参考。\n**建议咨询专业律师**，以获取针对您具体情况的法律意见。', '[]', '{\"rrfCount\": 0, \"rerankTop\": 0, \"isFallback\": true, \"bm25Results\": 0, \"originalQuery\": \"离婚时房产应该如何分割？\", \"vectorResults\": 0, \"rewrittenQuery\": \"离婚财产分割中不动产（特别是登记在一方或双方名下的房屋）的权属认定与分割规则\"}', 0, 0, NULL, NULL, '2026-03-21 19:14:22');
INSERT INTO `med_message` VALUES (11, 7, 'user', '被公司无故辞退，我有哪些法律权利？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 19:19:23');
INSERT INTO `med_message` VALUES (12, 7, 'assistant', '⚠️ 知识库未匹配到相关文献，以下为通用法律知识  \n\n被公司无故辞退（即用人单位无法定理由、未履行法定程序单方解除劳动合同），您依法享有以下主要权利：\n\n1. **主张违法解除赔偿金**  \n   根据《中华人民共和国劳动合同法》第48条、第87条：  \n   - 若劳动关系已实际解除，您可要求公司支付**赔偿金**＝经济补偿金 × 2；  \n   - 经济补偿金按工作年限计算：每满1年支付1个月工资；6个月以上不满1年按1年计；不满6个月支付0.5个月工资；  \n   - 月工资标准为解除前12个月平均工资（含奖金、津贴等货币性收入），高于当地社平工资3倍的，按3倍封顶，且补偿年限最高12年。\n\n2. **请求继续履行劳动合同**（如您希望返岗）  \n   依据《劳动合同法》第48条，您可选择要求公司继续履行合同，并补发违法解除期间的工资及社保待遇。但若劳动合同已不能继续履行（如岗位已撤销、信任关系破裂等），仲裁/法院可能支持赔偿金而非恢复劳动关系。\n\n3. **追索欠付劳动报酬与社保**  \n   - 包括被辞退当月工资、加班费、未休年休假工资、提成/绩效等应得而未付的款项；  \n   - 公司未依法缴纳社保的，可向当地社保经办机构投诉补缴（注意：社保补缴一般不通过劳动仲裁，而由行政途径处理）。\n\n4. **维权途径及时效**  \n   - 可向用人单位所在地或劳动合同履行地的**劳动人事争议仲裁委员会**申请劳动仲裁（免费，是诉讼前置程序）；  \n   - 仲裁时效为**知道或应当知道权利被侵害之日起1年内**（例如：收到《解除通知书》之日或实际离职日起算）；  \n   - 对仲裁裁决不服的，可在15日内向人民法院起诉。\n\n✅ 建议立即收集并保存证据：  \n- 劳动合同、工资条/银行流水、考勤记录、工作沟通记录（微信、邮件等）、解除通知（书面或录音）、社保缴费记录等。\n\n⚠️ 特别提示：所谓“无故辞退”需结合具体情形判断——如公司以“严重违纪”“不胜任工作”等理由解除，但无制度依据、未培训/调岗、未充分举证，也可能被认定为违法解除。\n\n由于个案差异大（如试用期、高管身份、地方裁审口径等），强烈建议尽快咨询当地专业劳动法律师或拨打12348公共法律服务热线获取针对性指导。\n\n---\nℹ️ **说明**：当前知识库中未找到与您问题高度相关的法律文献，以上回答基于通用法律知识，仅供参考。\n**建议咨询专业律师**，以获取针对您具体情况的法律意见。', '[]', '{\"rrfCount\": 0, \"rerankTop\": 0, \"isFallback\": true, \"bm25Results\": 0, \"originalQuery\": \"被公司无故辞退，我有哪些法律权利？\", \"vectorResults\": 0, \"rewrittenQuery\": \"用人单位单方解除劳动合同的法定条件、程序及违法解除的法律后果；劳动者在劳动合同被违法解除情形下的救济途径、赔偿标准与维权程序\"}', 0, 0, NULL, NULL, '2026-03-21 19:19:40');
INSERT INTO `med_message` VALUES (13, 8, 'user', '房东不退押金，我有哪些维权途径？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 19:52:33');
INSERT INTO `med_message` VALUES (14, 8, 'assistant', '⚠️ 知识库未匹配到相关文献，以下为通用法律知识  \n\n房东拒不退还押金属于常见的房屋租赁合同纠纷。根据《中华人民共和国民法典》第七百零三条、第七百一十条及第五百零九条等规定，押金性质为担保承租人依约履行合同义务（如按时交租、妥善使用房屋、结清费用、恢复原状等）的金钱担保，**并非预付租金或违约金**。是否应退、退多少，需结合合同约定与实际履约情况综合判断。\n\n您可依法采取以下维权途径（由易到难、由低成本到高成本）：\n\n1. **友好协商**  \n   - 保留微信/短信/邮件等沟通记录；  \n   - 明确要求房东说明不退理由（如主张房屋损坏、欠费等），并要求其提供证据（如维修发票、缴费单据、交接时的视频照片等）；  \n   - 若其理由不成立或证据不足，可指出其行为已构成违约。\n\n2. **向人民调解委员会申请调解**  \n   - 可联系居住地或房屋所在地的街道/社区人民调解委员会（免费、快捷、具法律效力）；  \n   - 达成调解协议后，可共同向法院申请司法确认，赋予强制执行力。\n\n3. **向当地住房城乡建设部门（住建局/房管局）投诉**  \n   - 部分地区已将租赁押金监管纳入行政管理范围（如北京、深圳等地有租赁资金监管规定）；  \n   - 可拨打12345政务服务便民热线或登录地方住建官网提交投诉，请求行政协调。\n\n4. **申请仲裁（如合同中有有效仲裁条款）**  \n   - 若租赁合同明确约定“因本合同引起的争议提交××仲裁委员会仲裁”，且条款合法有效，则应向约定仲裁机构申请仲裁（一裁终局，但费用和周期通常高于诉讼）。\n\n5. **向人民法院提起民事诉讼**  \n   - **管辖法院**：房屋所在地（不动产所在地）基层人民法院（即“专属管辖”）；  \n   - **诉讼请求**：可主张返还押金本金 + 占用期间利息（LPR标准）+ 合理维权费用（如诉讼费、必要交通费等）；  \n   - **关键证据**：  \n     ✓ 租赁合同（尤其押金条款、退租条件、违约责任）；  \n     ✓ 押金支付凭证（转账记录、收条等）；  \n     ✓ 退租交接记录（双方签字的《房屋交接确认书》、现场视频/照片、第三方见证等）；  \n     ✓ 水电燃气等费用结清凭证；  \n     ✓ 与房东就押金退还的全部沟通记录；  \n     ✓ 如有房屋损坏争议，可申请法院委托鉴定或提供维修前后的对比证据。\n\n✅ 温馨提示：  \n- 租赁关系终止后，房东应在合理期限内（通常7–15日，合同有约定从约定）完成验房并退还押金；无正当理由逾期不退，可能构成违约甚至恶意占有；  \n- 若房东以“墙面轻微污渍”“正常磨损”等理由扣款，一般不予支持（《民法典》第七百一十条：承租人按约定方法或根据租赁物性质使用，造成损耗的，不承担赔偿责任）；  \n- 切勿采取换锁、强占房屋、破坏设施等过激行为，否则可能反担法律责任。\n\n建议尽快固定证据，并视情况咨询当地执业律师或拨打12348公共法律服务热线获取免费专业指导。\n\n---\nℹ️ **说明**：当前知识库中未找到与您问题高度相关的法律文献，以上回答基于通用法律知识，仅供参考。\n**建议咨询专业律师**，以获取针对您具体情况的法律意见。', '[]', '{\"rrfCount\": 0, \"rerankTop\": 0, \"isFallback\": true, \"bm25Results\": 0, \"originalQuery\": \"房东不退押金，我有哪些维权途径？\", \"vectorResults\": 0, \"rewrittenQuery\": \"房屋租赁合同履行完毕后出租人拒不返还租赁保证金的法律救济途径\"}', 0, 0, NULL, NULL, '2026-03-21 19:52:52');
INSERT INTO `med_message` VALUES (15, 9, 'user', '被公司无故辞退，我有哪些法律权利？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 20:17:00');
INSERT INTO `med_message` VALUES (16, 9, 'assistant', '⚠️ 知识库未匹配到相关文献，以下为通用法律知识  \n\n若您被公司“无故辞退”（即用人单位未依据《中华人民共和国劳动合同法》规定的法定事由和程序单方解除劳动合同），您依法享有以下主要权利：\n\n1. **主张违法解除赔偿金**  \n   根据《劳动合同法》第48条、第87条：用人单位违法解除劳动合同的，劳动者有权要求继续履行合同；如不愿继续履行或劳动合同已不能继续履行，可主张**赔偿金**——标准为经济补偿金的**2倍**。  \n   ✅ 经济补偿金计算：按工作年限，每满1年支付1个月工资；6个月以上不满1年按1年计；不满6个月支付0.5个月工资（月工资指解除前12个月平均应得工资，含奖金、津贴等，但不超过当地社平工资3倍）。\n\n2. **获得书面解除通知及理由说明**  \n   公司单方解除必须出具书面通知，并载明解除依据（如《劳动合同法》第39、40、41条所列情形）。若未说明理由或理由不成立，即构成违法解除。\n\n3. **追索拖欠劳动报酬、加班费、未休年假工资等**  \n   辞退不影响您主张在职期间未结清的合法劳动权益（如工资、绩效、加班费、未休年假折算工资等），可一并主张。\n\n4. **要求出具离职证明**  \n   依据《劳动合同法》第50条，用人单位应在解除劳动合同时出具**离职证明**（写明劳动合同期限、解除日期、工作岗位、在本单位工作年限），不得以任何理由拒开或添加不实内容。\n\n5. **申请劳动仲裁是法定前置程序**  \n   如协商不成，须在**劳动关系终止之日起1年内**向用人单位所在地或劳动合同履行地的**劳动人事争议仲裁委员会**申请仲裁（免费，不收费）。对仲裁裁决不服的，可自收到裁决书之日起15日内向人民法院起诉。\n\n📌 重要提示：  \n- “无故辞退”需结合证据判断（如无书面通知、无正当理由、未履行民主程序、未提前通知/支付代通知金等）；  \n- 公司以“试用期不符合录用条件”“严重违纪”等为由解除的，须承担举证责任；  \n- 建议及时收集并保存证据：劳动合同、工资条/银行流水、考勤记录、微信/邮件沟通记录、辞退录音/书面通知等。\n\n✅ 强烈建议：此类案件高度依赖证据与程序细节，为切实保障权益，请尽快咨询当地劳动法律援助中心（12348热线）或委托专业劳动法律师介入处理。\n\n（注：以上依据《中华人民共和国劳动合同法》《劳动争议调解仲裁法》《最高人民法院关于审理劳动争议案件适用法律问题的解释（一）》等现行有效规定）\n\n---\nℹ️ **说明**：当前知识库中未找到与您问题高度相关的法律文献，以上回答基于通用法律知识，仅供参考。\n**建议咨询专业律师**，以获取针对您具体情况的法律意见。', '[]', '{\"rrfCount\": 0, \"rerankTop\": 0, \"isFallback\": true, \"bm25Results\": 0, \"originalQuery\": \"被公司无故辞退，我有哪些法律权利？\", \"vectorResults\": 0, \"rewrittenQuery\": \"用人单位单方解除劳动合同的法定条件、程序及违法解除的法律后果；劳动者在劳动合同被违法解除情形下的救济途径、赔偿标准与维权程序\"}', 0, 0, NULL, NULL, '2026-03-21 20:17:18');
INSERT INTO `med_message` VALUES (17, 10, 'user', '遭遇网络诈骗，如何维权追回损失？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 20:18:08');
INSERT INTO `med_message` VALUES (18, 10, 'assistant', '⚠️ 知识库未匹配到相关文献，以下为通用法律知识  \n\n遭遇网络诈骗后，维权追回损失需及时、依法、多途径协同推进，关键步骤如下：\n\n✅ 一、立即采取紧急措施  \n- **停止一切资金往来**：冻结涉案银行卡、支付账户（如微信、支付宝），可通过官方客服或银行电话银行申请临时止付；  \n- **保存完整证据**：包括聊天记录、转账凭证（含时间、金额、对方账号/户名）、网址链接、APP截图、通话录音、诈骗话术文本等，务必勿删除原始数据（建议导出备份）；  \n- **报警报案**：  \n  ▪ 拨打110或前往就近公安机关报案；  \n  ▪ 优先通过“国家网信办违法和不良信息举报中心”（[www.12377.cn](https://www.12377.cn)）或“公安部网络违法犯罪举报网站”（[www.110.cn](https://www.110.cn)）在线报案；  \n  ▪ 明确要求出具《受案回执》《立案通知书》（若达立案标准，公安机关应于7日内决定是否立案）。\n\n✅ 二、配合司法程序，争取资金拦截与追偿  \n- 若资金尚未转移出境且在48小时内报案，公安机关可启动“电信网络诈骗资金紧急止付”机制，通过“公安部电信诈骗案件侦办平台”协调银行冻结涉案账户；  \n- 立案后，积极配合侦查，提供线索；结案后如查实赃款，可依法申请发还（依据《公安机关办理刑事案件程序规定》第234条）；  \n- 若涉第三方平台（如虚假投资平台、钓鱼网站），可同步向市场监管、网信、金融监管等部门投诉（如银保监会12378、证监会12386）。\n\n✅ 三、民事救济补充（视情况）  \n- 若因平台未尽审核义务（如未实名认证、放任诈骗账号注册），可依《民法典》第1195–1197条主张网络服务提供者承担相应责任；  \n- 注意诉讼时效：一般为3年，自知道或应当知道权利受损及义务人之日起算，但刑事立案后时效中止。\n\n❗重要提醒：  \n- **切勿轻信“黑客追款”“内部渠道退款”等二次诈骗话术；**  \n- **所有维权均应通过正规执法、司法渠道，不支付任何“手续费”“保证金”；**  \n- 各地反诈中心已开通专线（如北京96110、上海962110），建议第一时间拨打属地反诈专线获取专业指导。\n\n📌 建议：因个案差异大（如资金流向、管辖权、证据完整性等），强烈建议尽快委托熟悉电信网络犯罪的律师介入，协助报案、调证、刑事附带民事诉讼或另行提起民事诉讼。\n\n如需，我可为您：  \n🔹 提供报案材料清单模板（含书面报案陈述要点）；  \n🔹 协助起草向平台/监管部门的正式投诉函；  \n🔹 解析常见诈骗类型（刷单、冒充公检法、虚假理财等）对应的取证重点。  \n请随时告知。\n\n---\nℹ️ **说明**：当前知识库中未找到与您问题高度相关的法律文献，以上回答基于通用法律知识，仅供参考。\n**建议咨询专业律师**，以获取针对您具体情况的法律意见。', '[]', '{\"rrfCount\": 0, \"rerankTop\": 0, \"isFallback\": true, \"bm25Results\": 0, \"originalQuery\": \"遭遇网络诈骗，如何维权追回损失？\", \"vectorResults\": 0, \"rewrittenQuery\": \"网络诈骗案件受害人维权途径及被骗资金追回机制\"}', 0, 0, NULL, NULL, '2026-03-21 20:18:25');
