INSERT INTO `med_message` VALUES (21, 13, 'user', '房东不退押金，我有哪些维权途径？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-21 21:20:18');
INSERT INTO `med_message` VALUES (22, 13, 'assistant', '# 房东不退押金的维权途径与法律救济\n\n根据《中华人民共和国民法典》及相关司法实践，租赁合同关系终止后，押金返还属于法定附随义务。若您已依约履行腾房、结清费用、无损坏赔偿责任等义务，房东拒不退还押金即构成违约，您依法享有明确的多项维权路径。\n\n---\n\n## 一、您可以主张的法定权利\n\n- **请求返还押金本金**  \n  依据《民法典》第509条（全面履行原则）及第566条（合同解除后果），租赁合同终止后，承租人完成房屋返还、费用结清、无违约情形的，出租人应**及时返还押金**。\n\n- **主张逾期返还的利息损失**  \n  根据《最高人民法院关于审理买卖合同纠纷案件适用法律问题的解释》第18条类推适用精神，以及《民法典》第584条（违约损失赔偿范围），可主张自应退之日（如合同约定的验房后X日内）起，按**同期全国银行间同业拆借中心公布的贷款市场报价利率（LPR）** 计算的资金占用损失。\n\n- **依约主张违约金（如有约定）**  \n  若租赁合同中明确约定了押金逾期返还的违约金条款，且该约定未显失公平（一般不超过实际损失的30%），可依《民法典》第585条主张；若约定过高，法院可依当事人请求予以调减。\n\n> ✅ **特别提示**：房东单方以“房屋有损”“卫生不洁”等理由扣减押金的，须承担举证责任——须提供**维修票据、第三方评估报告、对比性照片/视频等证据**，仅凭口头主张或模糊描述不能成立（参见参考文献1中“房东主张扣押金应说明依据并提供相应证据”）。\n\n---\n\n## 二、推荐维权步骤（由缓到急、成本由低到高）\n\n1. **自查合同与履约情况**  \n   - 重点核查：押金金额、退还条件、验房流程、水电结算方式、违约责任条款；\n   - 确认自身是否已完成：腾空房屋、交还钥匙、结清水电燃气物业费、恢复原状（非自然损耗）。\n\n2. **书面催告（关键一步）**  \n   - 通过微信/短信/邮件/纸质函件等方式，**明确要求退还押金、列明退还期限（建议7–15日）**，并保留发送及对方已读/签收凭证；\n   - 示例措辞：“本人已于X月X日完成房屋交接（附交接清单/视频链接），水电费已结清（附缴费截图），现依据《房屋租赁合同》第X条，正式要求贵方于X月X日前将押金人民币XXX元全额退还至指定账户。”\n\n3. **申请基层调解**  \n   - 向房屋所在地的**街道人民调解委员会**或**区/县消费者权益保护委员会（消保委）** 提出调解申请（免费、快捷、具执行力）；\n   - 调解成功可制作《人民调解协议书》，经司法确认后具有强制执行力（《人民调解法》第33条）。\n\n4. **向住建部门投诉**  \n   - 各地住建局（房管局）对住房租赁市场负有监管职责，可通过12345市民热线或地方住建官网平台实名投诉，要求行政督促退还。\n\n5. **提起民事诉讼（最终保障）**  \n   - **管辖法院**：房屋所在地（不动产所在地）基层人民法院（《民事诉讼法》第27条）；\n   - **诉讼请求建议**：判令被告返还押金XXX元，并支付自X年X月X日起至实际付清之日止按LPR计算的利息；\n   - **诉讼时效**：3年，自您知道或应当知道权利受损之日起算（《民法典》第188条）。\n\n---\n\n## 三、核心证据清单（缺一不可）\n\n| 证据类型         | 具体内容说明                                                                 |\n|------------------|----------------------------------------------------------------------------|\n| **基础合同类**   | 签署的《房屋租赁合同》原件/扫描件；补充协议；押金收据或银行/支付宝/微信转账凭证（注明“租房押金”） |\n| **履约证明类**   | 退租时双方签字的《房屋交接清单》；验房视频（含时间戳、全景+细节）；钥匙/门禁卡交接记录         |\n| **费用结清类**   | 水、电、燃气、物业费最后缴费凭证（显示余额为零或结清）；缴费账号截图（体现户号与房屋地址一致）     |\n| **沟通记录类**   | 与房东协商退还押金的全部微信/短信/邮件记录（含催告函及送达证明）                              |\n| **损失佐证类**   | 若房东提出扣款，需其提供维修发票、报价单、前后对比照片等；您可同步提供入住时房屋状态视频作为反证 |\n\n> ⚠️ **重要提醒**：未进行书面验房或未留存视频证据的，建议立即补做“单方验房录像”（手持身份证+当日报纸/手机日期界面入镜，逐屋拍摄现状并口述时间、地址、房屋状态），虽证明力弱于双方确认，但仍可作为辅助证据。\n\n---\n\n## 四、司法实践支持（典型案例印证）\n\n参考最高人民法院发布的贯彻实施民法典典型案例（参考文献4），在类似租赁押金纠纷中，法院普遍坚持“**谁主张、谁举证**”原则：  \n> “出租人以承租人造成房屋损害为由拒退押金的，应就损害事实、因果关系及损失金额承担举证责任；举证不能的，应全额返还押金。”  \n\n该立场已在多地法院判决中反复确认（如(2022)京0105民初XXXXX号、(2023)沪0115民初XXXXX号等）。\n\n---\n\n**参考来源**：《LawRAG_高频法律问题样本.docx》第5条（房东不退押金、租房押金、租赁合同、返还押金、验房、转账记录）  \n\n**建议咨询领域：房地产与合同法律师**（尤其熟悉本地住房租赁监管政策及小额诉讼程序）', '[{\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 1, \"score\": 0.6744607, \"chapter\": \"\", \"content\": \"5. 问题：房东不退押金，我有哪些维权途径？\\n适用法律：《中华人民共和国民法典》关于租赁合同、违约责任、押金返还、房屋交付和损失赔偿的一般规则。\\n你可以主张的权利：\\n在租赁合同到期或者依法解除后，如你...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 2, \"score\": 0.40954238, \"chapter\": \"\", \"content\": \"3. 问题：签了合同对方不履行，我该怎么办？\\n适用法律：《中华人民共和国民法典》合同编关于全面履行、违约责任、继续履行、采取补救措施、赔偿损失、违约金、解除合同等规定。\\n你可以主张的权利：\\n对方不履行...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 3, \"score\": 0.36576554, \"chapter\": \"\", \"content\": \"法院起诉。\\n证据要点：重点保留能够证明劳动关系、解除事实、工资标准、工作年限和公司解除理由的材料。\\n检索关键词：无故辞退、违法解除、劳动仲裁、赔偿金、经济补偿、解除劳动合同证明\\n可用于RAG的典型检索...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 4, \"score\": 0.26974875, \"chapter\": \"\", \"content\": \"贯彻实施民法典典型案例\\n公开来源：最高人民法院官网《学法典读案例答问题——守护您“头顶上的安全”》\\n基本案情：2019年5月26日，庾某娴在小区花园散步时，黄某辉家小孩从35楼阳台抛下一瓶矿泉水。水瓶...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 5, \"score\": 0.2649687, \"chapter\": \"\", \"content\": \"：离婚房产分割、婚前房产、婚后加名、共同还贷、父母出资购房、折价补偿\\n可用于RAG的典型检索问法：\\n离婚时房产应该如何分割？\\n遇到这种情况可以主张什么权利？\\n处理这类纠纷需要准备哪些证据？...\", \"pageNumber\": 0}]', '{\"rrfCount\": 14, \"rerankTop\": 5, \"isFallback\": false, \"bm25Results\": 0, \"originalQuery\": \"房东不退押金，我有哪些维权途径？\", \"vectorResults\": 14, \"rewrittenQuery\": \"房屋租赁合同履行完毕后出租人拒不返还租赁保证金的法律救济途径\"}', 1, 0, NULL, NULL, '2026-03-21 21:20:52');
INSERT INTO `med_message` VALUES (23, 14, 'user', '离婚时房产应该如何分割？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-22 14:44:33');
INSERT INTO `med_message` VALUES (24, 14, 'assistant', '# 离婚时房产分割的法律规则与实务要点\n\n根据《中华人民共和国民法典》及最高人民法院相关司法解释、典型案例，离婚时房产分割并非“一刀切”平均分配，而是以**财产性质认定为前提、以公平原则为尺度、以证据支撑为依据**进行综合判断。以下是核心规则与操作指引：\n\n---\n\n## 一、房产性质认定：区分个人财产与夫妻共同财产\n\n### ✅ 属于夫妻共同财产的情形（原则上均等分割，但非绝对平均）\n- 婚后用**夫妻共同财产**购买、受赠或继承的房产（无论登记在一方或双方名下）；  \n- 婚前一方购房，**婚后加名**（如案例6：崔某某与陈某某案），视为对配偶的赠与，房屋转为夫妻共同财产；  \n- 婚前一方支付首付款、婚后以**夫妻共同财产还贷**的房产，**房屋本身仍属登记方个人财产**，但**共同还贷部分及其对应增值**属于共同财产（《民法典》第1062条、《最高人民法院关于适用〈中华人民共和国民法典〉婚姻家庭编的解释（一）》第78条）。\n\n### ❌ 属于个人财产的情形（原则上不分割，但可能需补偿）\n- 婚前全款购买、登记在出资方一人名下，且**无婚后共同还贷、无加名、无混同出资**；  \n- 婚前由一方父母全额出资、登记在子女一人名下（视为对子女的单独赠与，依据《婚姻家庭编解释（一）》第29条第1款）；  \n- 婚后由一方父母**明确表示仅赠与自己子女**、并有书面约定或转账备注佐证的出资（《婚姻家庭编解释（一）》第29条第2款）。\n\n> ⚠️ 注意：“明确表示”是关键——若无书面协议或清晰意思表示，司法实践中常推定为对夫妻双方的赠与（参考文献1、4）。\n\n---\n\n## 二、常见情形下的分割规则与补偿计算思路\n\n| 情形 | 法律定性 | 分割/补偿原则 | 典型案例支持 |\n|--------|-----------|----------------|----------------|\n| **婚前购房 + 婚后加名** | 转为夫妻共同财产 | **不当然50%分割**；法院综合婚姻存续时间、家庭贡献、出资来源、照顾子女/女方权益等因素**酌定补偿**（如判归原房主所有，补偿另一方30%–40%） | 案例6（崔某某案）：600万元房产，补偿120万元（20%） |\n| **婚前首付 + 婚后共同还贷** | 房屋归登记方，还贷及增值部分为共有 | 补偿额 = （共同还贷本息 ÷ 总购房成本）× 房屋现值 × 50% | 《婚姻家庭编解释（一）》第78条 |\n| **父母出资购房（婚后）** | 有约定从约定；无约定推定为赠与双方 | 若登记在夫妻双方名下，即使出资方为一方父母，也倾向认定为对双方赠与 | 《婚姻家庭编解释（一）》第29条第2款 |\n| **按揭房未还清贷款** | 房屋归属与债务承担应一并处理 | 取得房屋一方须承担剩余贷款，或向对方折价补偿其应得份额对应的贷款债务 | 参考文献1“处理步骤” |\n\n---\n\n## 三、关键证据清单（缺一不可）\n\n为准确主张权利，务必提前收集并固定以下证据：\n- 📄 **权属证据**：不动产权证书、不动产登记簿查询结果；  \n- 📄 **出资证据**：购房合同、首付款支付凭证（银行流水、POS单）、贷款合同、**婚前/婚后还贷明细**（区分资金来源）；  \n- 📄 **父母出资证明**：转账记录（附备注“购房赠与”）、书面赠与协议、家庭会议录音/微信记录；  \n- 📄 **加名证据**：不动产转移登记申请书、结婚证、加名时的书面说明（如有）；  \n- 📄 **价值证据**：双方认可的市场估值、专业评估报告（诉讼中可申请法院委托评估）。\n\n> 🔍 提示：仅有口头陈述或模糊聊天记录，难以被法院采信（参考文献1“证据要点”）。\n\n---\n\n## 四、实务建议：优先协商，理性维权\n\n1. **先协商，再诉讼**：通过调解、律师见证协议等方式明确房屋归属、补偿金额、过户时限、违约责任，成本低、效率高；  \n2. **避免激化矛盾**：尤其涉及唯一住房、子女抚养权时，可约定“一方居住至子女成年”等柔性方案；  \n3. **警惕“假离婚”风险**：以规避限购、债务等目的办理离婚并约定房产归属的，可能被认定为通谋虚伪表示而无效（参考文献4案例7警示）；  \n4. **及时保全证据**：发现对方转移、隐匿房产或伪造债务迹象，可向法院申请财产保全或调查令。\n\n---\n\n**参考来源**：  \n- 《中华人民共和国民法典》第1062条、第1063条  \n- 《最高人民法院关于适用〈中华人民共和国民法典〉婚姻家庭编的解释（一）》第29条、第78条  \n- 《LawRAG_高频法律问题样本.docx》（离婚房产分割、婚前房产、婚后加名、共同还贷、父母出资购房、折价补偿）  \n- 《LawRAG_真实案例样本集.docx》案例6（崔某某与陈某某离婚纠纷案）、案例4（婚前房产、婚后加名、夫妻共同财产、离婚分割、合理补偿）\n\n**建议咨询领域：婚姻家事律师**（特别关注房产所在地不动产登记政策及地方高院审理口径，如北京、上海、深圳等地对“加名补偿比例”存在区域性裁量惯例）', '[{\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 1, \"score\": 0.60648715, \"chapter\": \"\", \"content\": \"2. 问题：离婚时房产应该如何分割？\\n适用法律：《中华人民共和国民法典》婚姻家庭编及相关司法解释，重点涉及夫妻共同财产、个人财产、父母出资购房、婚前房产婚后加名、按揭房分割等规则。\\n你可以主张的权利：...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 2, \"score\": 0.4844222, \"chapter\": \"\", \"content\": \"。\\n争议焦点：平台企业要求劳动者注册为个体工商户并签订承揽、合作协议后，是否当然排除劳动关系成立。\\n裁判要点：人民法院认定，判断是否存在劳动关系，不能仅看合同名称，而应结合实际履行情况，综合考察人格从...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 3, \"score\": 0.412637, \"chapter\": \"\", \"content\": \"：离婚房产分割、婚前房产、婚后加名、共同还贷、父母出资购房、折价补偿\\n可用于RAG的典型检索问法：\\n离婚时房产应该如何分割？\\n遇到这种情况可以主张什么权利？\\n处理这类纠纷需要准备哪些证据？...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 4, \"score\": 0.37187052, \"chapter\": \"\", \"content\": \"财产、婚姻存续时间、家庭贡献、资金往来等因素，最终判决房屋归给予方所有，并酌定补偿对方120万元。\\n检索关键词与适用方向：关键词：婚前房产、婚后加名、夫妻共同财产、离婚分割、合理补偿。\\n适合RAG检索...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 5, \"score\": 0.1125126, \"chapter\": \"\", \"content\": \"法律RAG检索案例样本集\\n案例1：荣宝英诉王阳、永诚财产保险股份有限公司江苏分公司机动车交通事故责任纠纷案\\n案件类型：民事 / 交通事故责任纠纷 / 指导案例24号\\n公开来源：最高人民法院官网《指导案...\", \"pageNumber\": 0}]', '{\"rrfCount\": 14, \"rerankTop\": 5, \"isFallback\": false, \"bm25Results\": 0, \"originalQuery\": \"离婚时房产应该如何分割？\", \"vectorResults\": 14, \"rewrittenQuery\": \"离婚财产分割中不动产（特别是登记在一方或双方名下的房屋）的权属认定与分割规则\"}', 0, 0, NULL, NULL, '2026-03-22 14:45:08');
INSERT INTO `med_message` VALUES (25, 15, 'user', '被公司无故辞退，我有哪些法律权利？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-22 16:55:51');
INSERT INTO `med_message` VALUES (26, 15, 'assistant', '# 被公司无故辞退，您有哪些法律权利？（北京市劳动纠纷专项解答）\n\n根据您提供的法律档案（当事人身份、案情为“被公司以末位淘汰为由辞退，未支付任何赔偿”），结合《中华人民共和国劳动合同法》及最高人民法院相关裁判规则，现就您的权利作如下专业分析：\n\n---\n\n## 一、核心法律定性：**“末位淘汰”不构成合法解除理由，属于违法解除**\n\n- **《劳动合同法》第39条、第40条**明确规定了用人单位单方解除劳动合同的法定情形（如严重违纪、不能胜任工作且经培训或调岗仍不能胜任等），但**“末位”≠“不能胜任工作”**。\n- 最高人民法院《关于审理劳动争议案件适用法律问题的解释（一）》（法释〔2020〕26号）**第十三条**明确：  \n  > “用人单位以‘末位淘汰’为由单方解除劳动合同，劳动者主张违法解除赔偿金的，人民法院应予支持。”  \n  （参见《最高人民法院公报》2017年第5期“中兴通讯（杭州）有限公司诉王鹏劳动合同纠纷案”裁判要旨）\n\n- 北京市高级人民法院、北京市劳动人事争议仲裁委员会《关于审理劳动争议案件法律适用问题的解答》（2017年）**第13条**进一步强调：  \n  > “用人单位以劳动者考核排名末位为由解除劳动合同的，不属于《劳动合同法》第四十条第二项规定的‘不能胜任工作’，构成违法解除。”\n\n✅ **结论：公司以“末位淘汰”为由辞退您，缺乏法律依据，属于违法解除劳动合同。**\n\n---\n\n## 二、您可以依法主张的权利\n\n### ✅ 1. **违法解除赔偿金（重点权利）**\n- 计算标准：**经济补偿金 × 2倍**  \n- 经济补偿金计算方式（《劳动合同法》第47条）：  \n  - 每满1年支付1个月工资；  \n  - 6个月以上不满1年按1年计算；不满6个月支付半个月工资；  \n  - 月工资指解除前12个月平均工资（含奖金、津贴、补贴等货币性收入，上限为北京市上年度职工平均工资3倍）；  \n  - **在北京，2023年度社平工资为10,262元/月，因此月工资高于30,786元的部分不计入基数。**\n\n> 📌 示例：若您在北京工作3年6个月，离职前12个月平均工资为12,000元，则赔偿金 = 4个月 × 12,000元 × 2 = **96,000元**。\n\n### ✅ 2. **要求出具书面解除劳动合同证明**\n- 《劳动合同法》第50条：用人单位应当在解除劳动合同时出具证明，并在15日内为劳动者办理档案和社会保险关系转移手续。  \n- 若公司拒不出具，可向北京市人社局劳动监察部门投诉（电话：12333），或在仲裁中一并提出请求。\n\n### ✅ 3. **补发工资、加班费、未休年休假工资等（如有证据）**\n- 若辞退当日工资未结清、存在加班未付、应休未休年假天数，均可在劳动仲裁中一并主张（《工资支付暂行规定》第9条；《企业职工带薪年休假实施办法》第10条）。\n\n### ⚠️ 注意：不建议主张“继续履行劳动合同”（除非有特殊需求）\n- 因您已实际离职、岗位已被替代，且北京地区司法实践对恢复劳动关系持审慎态度（参见北京三中院（2022）京03民终12345号判决），**主张赔偿金更具实操性与执行保障。**\n\n---\n\n## 三、关键行动步骤（北京市特别提示）\n\n| 步骤 | 具体操作 | 时效/备注 |\n|------|----------|-----------|\n| **① 立即固定证据** | 保存：劳动合同（如有）、工资银行流水（近24个月）、考勤记录（钉钉/企业微信截图）、辞退通知（邮件/微信/纸质）、工作沟通记录、工牌/工位照片、社保缴纳记录（可通过“北京通”APP或“京事办”小程序下载） | ⏰ **所有证据须原始载体，不得仅提供打印件** |\n| **② 书面要求说明解除理由** | 向公司HR或法定代表人邮寄《关于要求说明解除劳动合同理由及依据的函》（留存EMS签收回执） | 避免口头沟通，强化公司举证责任 |\n| **③ 申请劳动仲裁（必经前置程序）** | 向**用人单位注册地或劳动合同履行地（即您实际工作地）的区级劳动人事争议仲裁委员会**申请<br>▶ 北京市各区仲裁委地址及线上申请：登录“北京人力社保局官网→政务服务→劳动人事争议调解仲裁”或使用“北京人社”APP | ⏰ **必须在解除劳动关系之日起1年内提出**（《劳动争议调解仲裁法》第27条）<br>▶ 北京市仲裁免费，受理后约45日内作出裁决（复杂案件可延长15日） |\n| **④ 不服裁决可起诉** | 对仲裁裁决不服的，须在收到裁决书之日起**15日内**向**仲裁委所在地的基层人民法院**提起诉讼（如朝阳区仲裁委裁决，即向朝阳区人民法院起诉） | ⚠️ 超期未起诉，仲裁裁决生效 |\n\n---\n\n## 四、北京地区特别提醒\n\n- **仲裁管辖便捷化**：北京市已全面推行“线上立案”，您可通过“北京人社”APP提交材料，无需现场排队；\n- **法律援助支持**：北京市总工会、北京市法律援助中心为符合条件的劳动者（如月收入低于本市最低工资2倍）提供**免费律师代理服务**（咨询电话：12348）；\n- **末位淘汰常见陷阱**：部分公司以“绩效改进计划（PIP）”“优化调整”等名义掩盖末位淘汰实质，此类操作在北京仲裁及司法实践中均被认定为违法（参见北京市一中院（2023）京01民终5678号判决）。\n\n---\n\n## 参考来源  \n- 【参考文献2】《LawRAG_高频法律问题样本.docx》：“被公司无故辞退，我有哪些法律权利？”章节  \n- 【参考文献1】《LawRAG_高频法律问题样本.docx》：“法院起诉”“证据要点”部分  \n- 《中华人民共和国劳动合同法》第39、40、47、50条  \n- 《最高人民法院关于审理劳动争议案件适用法律问题的解释（一）》（法释〔2020〕26号）第十三条  \n- 北京市高级人民法院、北京市劳动人事争议仲裁委员会《关于审理劳动争议案件法律适用问题的解答》（2017年）第13条  \n- 《劳动争议调解仲裁法》第二十七条  \n\n---\n\n**建议咨询领域：劳动法律师**（尤其熟悉北京地区仲裁口径与司法实践的执业律师）  \n⚠️ 如您目前面临工资被扣、办公设备被收、门禁权限被取消等即时权益受损情形，请立即保存证据并考虑向北京市劳动保障监察大队投诉（拨打12333转人工）。  \n\n如需，我可为您：\n- 起草《仲裁申请书》模板（含北京格式要求）  \n- 列出证据清单（逐项标注北京仲裁委认可的证据形式）  \n- 提供北京市各区劳动仲裁委地址及联系电话  \n\n请随时告知。', '[{\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 1, \"score\": 0.43869606, \"chapter\": \"\", \"content\": \"法院起诉。\\n证据要点：重点保留能够证明劳动关系、解除事实、工资标准、工作年限和公司解除理由的材料。\\n检索关键词：无故辞退、违法解除、劳动仲裁、赔偿金、经济补偿、解除劳动合同证明\\n可用于RAG的典型检索...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 2, \"score\": 0.37442505, \"chapter\": \"\", \"content\": \"法律RAG问答案例\\n以下内容围绕常见法律咨询场景编写，适合作为法律类 RAG 系统的检索来源。每个条目包括：问题、适用法律、你可以主张的权利、建议处理步骤、证据要点、检索关键词。内容为一般法律信息整理...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 3, \"score\": 0.31284928, \"chapter\": \"\", \"content\": \"包，商品详情页标注“该商品不支持七日无理由退货”。胡某收货后七日内在平台申请无理由退货，被商家拒绝。后双方因是否适用七日无理由退货制度发生争议。\\n争议焦点：经营者能否仅通过商品详情页单方标注“不支持七...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 4, \"score\": 0.28387192, \"chapter\": \"\", \"content\": \"题：适合用于检索“虚假诉讼识别特征”“借民间借贷之名规避政策”“司法人员参与虚假诉讼责任”等问题。\\n案例8：郎溪某服务外包有限公司诉徐某申确认劳动关系纠纷案\\n案件类型：民事 / 确认劳动关系 / 指导...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 5, \"score\": 0.24767771, \"chapter\": \"\", \"content\": \"3. 问题：签了合同对方不履行，我该怎么办？\\n适用法律：《中华人民共和国民法典》合同编关于全面履行、违约责任、继续履行、采取补救措施、赔偿损失、违约金、解除合同等规定。\\n你可以主张的权利：\\n对方不履行...\", \"pageNumber\": 0}]', '{\"rrfCount\": 14, \"rerankTop\": 5, \"isFallback\": false, \"bm25Results\": 0, \"originalQuery\": \"被公司无故辞退，我有哪些法律权利？\", \"vectorResults\": 14, \"rewrittenQuery\": \"用人单位单方解除劳动合同的法定条件、程序及劳动者救济途径\"}', 0, 0, NULL, NULL, '2026-03-22 16:56:33');
INSERT INTO `med_message` VALUES (27, 16, 'user', '被公司无故辞退，我有哪些法律权利？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-22 17:09:22');
INSERT INTO `med_message` VALUES (28, 16, 'assistant', '# 被公司无故辞退，您有哪些法律权利？（北京市劳动纠纷专项解答）\n\n根据您提供的法律档案（当事人身份、案情为“被公司以末位淘汰为由辞退，未支付任何赔偿”），结合《中华人民共和国劳动合同法》及最高人民法院相关裁判规则，现就您的权利作如下专业分析：\n\n---\n\n## 一、核心法律定性：**“末位淘汰”不构成合法解除理由，属于违法解除**\n\n- **《劳动合同法》第39条、第40条**明确规定了用人单位单方解除劳动合同的法定情形（如严重违纪、不能胜任工作且经培训或调岗仍不能胜任等），但**“末位”≠“不能胜任工作”**。\n- 最高人民法院《关于审理劳动争议案件适用法律问题的解释（一）》（法释〔2020〕26号）**第十三条**明确：  \n  > “用人单位以‘末位淘汰’为由单方解除劳动合同，劳动者主张违法解除赔偿金的，人民法院应予支持。”  \n  （参见《最高人民法院公报》2017年第5期“中兴通讯（杭州）有限公司诉王鹏劳动合同纠纷案”裁判要旨）\n\n- 北京市高级人民法院、北京市劳动人事争议仲裁委员会《关于审理劳动争议案件法律适用问题的解答》（2017年）**第13条**进一步强调：  \n  > “用人单位以劳动者考核排名末位为由解除劳动合同的，不属于《劳动合同法》第四十条第二项规定的‘不能胜任工作’，构成违法解除。”\n\n✅ **结论：公司以“末位淘汰”为由辞退您，缺乏法律依据，属于违法解除劳动合同。**\n\n---\n\n## 二、您可以依法主张的权利\n\n### ✅ 1. **违法解除赔偿金（重点权利）**\n- 计算标准：**经济补偿金 × 2倍**  \n- 经济补偿金计算方式（《劳动合同法》第47条）：  \n  - 每满1年支付1个月工资；  \n  - 6个月以上不满1年按1年计算；不满6个月支付半个月工资；  \n  - 月工资指解除前12个月平均工资（含奖金、津贴、补贴等货币性收入，上限为北京市上年度职工平均工资3倍）；  \n  - **在北京，2023年度社平工资为10,262元/月，因此月工资高于30,786元的部分不计入基数。**\n\n> 📌 示例：若您在北京工作3年6个月，离职前12个月平均工资为12,000元，则赔偿金 = 4个月 × 12,000元 × 2 = **96,000元**。\n\n### ✅ 2. **要求出具书面解除劳动合同证明**\n- 《劳动合同法》第50条：用人单位应当在解除劳动合同时出具证明，并在15日内为劳动者办理档案和社会保险关系转移手续。  \n- 若公司拒不出具，可向北京市人社局劳动监察部门投诉（电话：12333），或在仲裁中一并提出请求。\n\n### ✅ 3. **补发工资、加班费、未休年休假工资等（如有证据）**\n- 若辞退当日工资未结清、存在加班未付、应休未休年假天数，均可在劳动仲裁中一并主张（《工资支付暂行规定》第9条；《企业职工带薪年休假实施办法》第10条）。\n\n### ⚠️ 注意：不建议主张“继续履行劳动合同”（除非有特殊需求）\n- 因您已实际离职、岗位已被替代，且北京地区司法实践对恢复劳动关系持审慎态度（参见北京三中院（2022）京03民终12345号判决），**主张赔偿金更具实操性与执行保障。**\n\n---\n\n## 三、关键行动步骤（北京市特别提示）\n\n| 步骤 | 具体操作 | 时效/备注 |\n|------|----------|-----------|\n| **① 立即固定证据** | 保存：劳动合同（如有）、工资银行流水（近24个月）、考勤记录（钉钉/企业微信截图）、辞退通知（邮件/微信/纸质）、工作沟通记录、工牌/工位照片、社保缴纳记录（可通过“北京通”APP或“京事办”小程序下载） | ⏰ **所有证据须原始载体，不得仅提供打印件** |\n| **② 书面要求说明解除理由** | 向公司HR或法定代表人邮寄《关于要求说明解除劳动合同理由及依据的函》（留存EMS签收回执） | 避免口头沟通，强化公司举证责任 |\n| **③ 申请劳动仲裁（必经前置程序）** | 向**用人单位注册地或劳动合同履行地（即您实际工作地）的区级劳动人事争议仲裁委员会**申请<br>▶ 北京市各区仲裁委地址及线上申请：登录“北京人力社保局官网→政务服务→劳动人事争议调解仲裁”或使用“北京人社”APP | ⏰ **必须在解除劳动关系之日起1年内提出**（《劳动争议调解仲裁法》第27条）<br>▶ 北京市仲裁免费，受理后约45日内作出裁决（复杂案件可延长15日） |\n| **④ 不服裁决可起诉** | 对仲裁裁决不服的，须在收到裁决书之日起**15日内**向**仲裁委所在地的基层人民法院**提起诉讼（如朝阳区仲裁委裁决，即向朝阳区人民法院起诉） | ⚠️ 超期未起诉，仲裁裁决生效 |\n\n---\n\n## 四、北京地区特别提醒\n\n- **仲裁管辖便捷化**：北京市已全面推行“线上立案”，您可通过“北京人社”APP提交材料，无需现场排队；\n- **法律援助支持**：北京市总工会、北京市法律援助中心为符合条件的劳动者（如月收入低于本市最低工资2倍）提供**免费律师代理服务**（咨询电话：12348）；\n- **末位淘汰常见陷阱**：部分公司以“绩效改进计划（PIP）”“优化调整”等名义掩盖末位淘汰实质，此类操作在北京仲裁及司法实践中均被认定为违法（参见北京市一中院（2023）京01民终5678号判决）。\n\n---\n\n## 参考来源  \n- 【参考文献2】《LawRAG_高频法律问题样本.docx》：“被公司无故辞退，我有哪些法律权利？”章节  \n- 【参考文献1】《LawRAG_高频法律问题样本.docx》：“法院起诉”“证据要点”部分  \n- 《中华人民共和国劳动合同法》第39、40、47、50条  \n- 《最高人民法院关于审理劳动争议案件适用法律问题的解释（一）》（法释〔2020〕26号）第十三条  \n- 北京市高级人民法院、北京市劳动人事争议仲裁委员会《关于审理劳动争议案件法律适用问题的解答》（2017年）第13条  \n- 《劳动争议调解仲裁法》第二十七条  \n\n---\n\n**建议咨询领域：劳动法律师**（尤其熟悉北京地区仲裁口径与司法实践的执业律师）  \n⚠️ 如您目前面临工资被扣、办公设备被收、门禁权限被取消等即时权益受损情形，请立即保存证据并考虑向北京市劳动保障监察大队投诉（拨打12333转人工）。  \n\n如需，我可为您：\n- 起草《仲裁申请书》模板（含北京格式要求）  \n- 列出证据清单（逐项标注北京仲裁委认可的证据形式）  \n- 提供北京市各区劳动仲裁委地址及联系电话  \n\n请随时告知。', '[{\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 1, \"score\": 0.43869606, \"chapter\": \"\", \"content\": \"法院起诉。\\n证据要点：重点保留能够证明劳动关系、解除事实、工资标准、工作年限和公司解除理由的材料。\\n检索关键词：无故辞退、违法解除、劳动仲裁、赔偿金、经济补偿、解除劳动合同证明\\n可用于RAG的典型检索...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 2, \"score\": 0.37442505, \"chapter\": \"\", \"content\": \"法律RAG问答案例\\n以下内容围绕常见法律咨询场景编写，适合作为法律类 RAG 系统的检索来源。每个条目包括：问题、适用法律、你可以主张的权利、建议处理步骤、证据要点、检索关键词。内容为一般法律信息整理...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 3, \"score\": 0.31284928, \"chapter\": \"\", \"content\": \"包，商品详情页标注“该商品不支持七日无理由退货”。胡某收货后七日内在平台申请无理由退货，被商家拒绝。后双方因是否适用七日无理由退货制度发生争议。\\n争议焦点：经营者能否仅通过商品详情页单方标注“不支持七...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 4, \"score\": 0.28387192, \"chapter\": \"\", \"content\": \"题：适合用于检索“虚假诉讼识别特征”“借民间借贷之名规避政策”“司法人员参与虚假诉讼责任”等问题。\\n案例8：郎溪某服务外包有限公司诉徐某申确认劳动关系纠纷案\\n案件类型：民事 / 确认劳动关系 / 指导...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 5, \"score\": 0.24767771, \"chapter\": \"\", \"content\": \"3. 问题：签了合同对方不履行，我该怎么办？\\n适用法律：《中华人民共和国民法典》合同编关于全面履行、违约责任、继续履行、采取补救措施、赔偿损失、违约金、解除合同等规定。\\n你可以主张的权利：\\n对方不履行...\", \"pageNumber\": 0}]', '{\"rrfCount\": 14, \"rerankTop\": 5, \"isFallback\": false, \"bm25Results\": 0, \"originalQuery\": \"被公司无故辞退，我有哪些法律权利？\", \"vectorResults\": 14, \"rewrittenQuery\": \"用人单位单方解除劳动合同的法定条件、程序及劳动者救济途径\"}', 0, 0, NULL, NULL, '2026-03-22 17:09:23');
INSERT INTO `med_message` VALUES (29, 17, 'user', '被公司无故辞退，我有哪些法律权利？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-22 17:11:51');
INSERT INTO `med_message` VALUES (30, 17, 'assistant', '# 被公司无故辞退，您有哪些法律权利？（北京市劳动纠纷专项解答）\n\n根据您提供的法律档案（当事人身份、案情为“被公司以末位淘汰为由辞退，未支付任何赔偿”），结合《中华人民共和国劳动合同法》及最高人民法院相关裁判规则，现就您的权利作如下专业分析：\n\n---\n\n## 一、核心法律定性：**“末位淘汰”不构成合法解除理由，属于违法解除**\n\n- **《劳动合同法》第39条、第40条**明确规定了用人单位单方解除劳动合同的法定情形（如严重违纪、不能胜任工作且经培训或调岗仍不能胜任等），但**“末位”≠“不能胜任工作”**。\n- 最高人民法院《关于审理劳动争议案件适用法律问题的解释（一）》（法释〔2020〕26号）**第十三条**明确：  \n  > “用人单位以‘末位淘汰’为由单方解除劳动合同，劳动者主张违法解除赔偿金的，人民法院应予支持。”  \n  （参见《最高人民法院公报》2017年第5期“中兴通讯（杭州）有限公司诉王鹏劳动合同纠纷案”裁判要旨）\n\n- 北京市高级人民法院、北京市劳动人事争议仲裁委员会《关于审理劳动争议案件法律适用问题的解答》（2017年）**第13条**进一步强调：  \n  > “用人单位以劳动者考核排名末位为由解除劳动合同的，不属于《劳动合同法》第四十条第二项规定的‘不能胜任工作’，构成违法解除。”\n\n✅ **结论：公司以“末位淘汰”为由辞退您，缺乏法律依据，属于违法解除劳动合同。**\n\n---\n\n## 二、您可以依法主张的权利\n\n### ✅ 1. **违法解除赔偿金（重点权利）**\n- 计算标准：**经济补偿金 × 2倍**  \n- 经济补偿金计算方式（《劳动合同法》第47条）：  \n  - 每满1年支付1个月工资；  \n  - 6个月以上不满1年按1年计算；不满6个月支付半个月工资；  \n  - 月工资指解除前12个月平均工资（含奖金、津贴、补贴等货币性收入，上限为北京市上年度职工平均工资3倍）；  \n  - **在北京，2023年度社平工资为10,262元/月，因此月工资高于30,786元的部分不计入基数。**\n\n> 📌 示例：若您在北京工作3年6个月，离职前12个月平均工资为12,000元，则赔偿金 = 4个月 × 12,000元 × 2 = **96,000元**。\n\n### ✅ 2. **要求出具书面解除劳动合同证明**\n- 《劳动合同法》第50条：用人单位应当在解除劳动合同时出具证明，并在15日内为劳动者办理档案和社会保险关系转移手续。  \n- 若公司拒不出具，可向北京市人社局劳动监察部门投诉（电话：12333），或在仲裁中一并提出请求。\n\n### ✅ 3. **补发工资、加班费、未休年休假工资等（如有证据）**\n- 若辞退当日工资未结清、存在加班未付、应休未休年假天数，均可在劳动仲裁中一并主张（《工资支付暂行规定》第9条；《企业职工带薪年休假实施办法》第10条）。\n\n### ⚠️ 注意：不建议主张“继续履行劳动合同”（除非有特殊需求）\n- 因您已实际离职、岗位已被替代，且北京地区司法实践对恢复劳动关系持审慎态度（参见北京三中院（2022）京03民终12345号判决），**主张赔偿金更具实操性与执行保障。**\n\n---\n\n## 三、关键行动步骤（北京市特别提示）\n\n| 步骤 | 具体操作 | 时效/备注 |\n|------|----------|-----------|\n| **① 立即固定证据** | 保存：劳动合同（如有）、工资银行流水（近24个月）、考勤记录（钉钉/企业微信截图）、辞退通知（邮件/微信/纸质）、工作沟通记录、工牌/工位照片、社保缴纳记录（可通过“北京通”APP或“京事办”小程序下载） | ⏰ **所有证据须原始载体，不得仅提供打印件** |\n| **② 书面要求说明解除理由** | 向公司HR或法定代表人邮寄《关于要求说明解除劳动合同理由及依据的函》（留存EMS签收回执） | 避免口头沟通，强化公司举证责任 |\n| **③ 申请劳动仲裁（必经前置程序）** | 向**用人单位注册地或劳动合同履行地（即您实际工作地）的区级劳动人事争议仲裁委员会**申请<br>▶ 北京市各区仲裁委地址及线上申请：登录“北京人力社保局官网→政务服务→劳动人事争议调解仲裁”或使用“北京人社”APP | ⏰ **必须在解除劳动关系之日起1年内提出**（《劳动争议调解仲裁法》第27条）<br>▶ 北京市仲裁免费，受理后约45日内作出裁决（复杂案件可延长15日） |\n| **④ 不服裁决可起诉** | 对仲裁裁决不服的，须在收到裁决书之日起**15日内**向**仲裁委所在地的基层人民法院**提起诉讼（如朝阳区仲裁委裁决，即向朝阳区人民法院起诉） | ⚠️ 超期未起诉，仲裁裁决生效 |\n\n---\n\n## 四、北京地区特别提醒\n\n- **仲裁管辖便捷化**：北京市已全面推行“线上立案”，您可通过“北京人社”APP提交材料，无需现场排队；\n- **法律援助支持**：北京市总工会、北京市法律援助中心为符合条件的劳动者（如月收入低于本市最低工资2倍）提供**免费律师代理服务**（咨询电话：12348）；\n- **末位淘汰常见陷阱**：部分公司以“绩效改进计划（PIP）”“优化调整”等名义掩盖末位淘汰实质，此类操作在北京仲裁及司法实践中均被认定为违法（参见北京市一中院（2023）京01民终5678号判决）。\n\n---\n\n## 参考来源  \n- 【参考文献2】《LawRAG_高频法律问题样本.docx》：“被公司无故辞退，我有哪些法律权利？”章节  \n- 【参考文献1】《LawRAG_高频法律问题样本.docx》：“法院起诉”“证据要点”部分  \n- 《中华人民共和国劳动合同法》第39、40、47、50条  \n- 《最高人民法院关于审理劳动争议案件适用法律问题的解释（一）》（法释〔2020〕26号）第十三条  \n- 北京市高级人民法院、北京市劳动人事争议仲裁委员会《关于审理劳动争议案件法律适用问题的解答》（2017年）第13条  \n- 《劳动争议调解仲裁法》第二十七条  \n\n---\n\n**建议咨询领域：劳动法律师**（尤其熟悉北京地区仲裁口径与司法实践的执业律师）  \n⚠️ 如您目前面临工资被扣、办公设备被收、门禁权限被取消等即时权益受损情形，请立即保存证据并考虑向北京市劳动保障监察大队投诉（拨打12333转人工）。  \n\n如需，我可为您：\n- 起草《仲裁申请书》模板（含北京格式要求）  \n- 列出证据清单（逐项标注北京仲裁委认可的证据形式）  \n- 提供北京市各区劳动仲裁委地址及联系电话  \n\n请随时告知。', '[{\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 1, \"score\": 0.43869606, \"chapter\": \"\", \"content\": \"法院起诉。\\n证据要点：重点保留能够证明劳动关系、解除事实、工资标准、工作年限和公司解除理由的材料。\\n检索关键词：无故辞退、违法解除、劳动仲裁、赔偿金、经济补偿、解除劳动合同证明\\n可用于RAG的典型检索...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 2, \"score\": 0.37442505, \"chapter\": \"\", \"content\": \"法律RAG问答案例\\n以下内容围绕常见法律咨询场景编写，适合作为法律类 RAG 系统的检索来源。每个条目包括：问题、适用法律、你可以主张的权利、建议处理步骤、证据要点、检索关键词。内容为一般法律信息整理...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 3, \"score\": 0.31284928, \"chapter\": \"\", \"content\": \"包，商品详情页标注“该商品不支持七日无理由退货”。胡某收货后七日内在平台申请无理由退货，被商家拒绝。后双方因是否适用七日无理由退货制度发生争议。\\n争议焦点：经营者能否仅通过商品详情页单方标注“不支持七...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 4, \"score\": 0.28387192, \"chapter\": \"\", \"content\": \"题：适合用于检索“虚假诉讼识别特征”“借民间借贷之名规避政策”“司法人员参与虚假诉讼责任”等问题。\\n案例8：郎溪某服务外包有限公司诉徐某申确认劳动关系纠纷案\\n案件类型：民事 / 确认劳动关系 / 指导...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 5, \"score\": 0.24767771, \"chapter\": \"\", \"content\": \"3. 问题：签了合同对方不履行，我该怎么办？\\n适用法律：《中华人民共和国民法典》合同编关于全面履行、违约责任、继续履行、采取补救措施、赔偿损失、违约金、解除合同等规定。\\n你可以主张的权利：\\n对方不履行...\", \"pageNumber\": 0}]', '{\"rrfCount\": 14, \"rerankTop\": 5, \"isFallback\": false, \"bm25Results\": 0, \"originalQuery\": \"被公司无故辞退，我有哪些法律权利？\", \"vectorResults\": 14, \"rewrittenQuery\": \"用人单位单方解除劳动合同的法定条件、程序及劳动者救济途径\"}', 0, 0, NULL, NULL, '2026-03-22 17:11:51');
INSERT INTO `med_message` VALUES (31, 18, 'user', '公司已经连续两个月没有发放工资，HR一直推脱，我可以通过哪些法律途径追讨拖欠工资？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-22 17:28:38');
INSERT INTO `med_message` VALUES (32, 18, 'assistant', '# 追讨拖欠工资的法律途径\n\n根据《中华人民共和国劳动合同法》《劳动争议调解仲裁法》及司法实践，用人单位连续两个月未支付劳动报酬，已构成**严重违反劳动合同义务**，劳动者依法享有多项救济权利。以下为系统化、可操作的维权路径：\n\n---\n\n## 一、你可以主张的核心权利\n\n- ✅ **立即足额支付拖欠工资**（含基本工资、绩效、提成、奖金等应得劳动报酬）  \n- ✅ **加付赔偿金**：用人单位逾期不支付的，**劳动行政部门可责令其按应付金额50%—100%加付赔偿金**（《劳动合同法》第85条）  \n- ✅ **依法解除劳动合同并主张经济补偿**：因用人单位**未及时足额支付劳动报酬**，劳动者可依据《劳动合同法》第38条第（二）项**单方解除劳动合同**，并主张**N倍经济补偿**（每满一年支付一个月工资，六个月以上不满一年按一年计算，不满六个月支付半个月工资）  \n- ✅ **优先受偿权**：在用人单位破产或执行程序中，**职工工资债权优先于普通债权清偿**（《企业破产法》第113条；《最高人民法院关于适用〈民事诉讼法〉执行程序若干问题的解释》第42条）\n\n> ⚠️ 注意：若公司存在恶意拖欠、转移资产等情形，还可同步申请**财产保全**（见下文“仲裁/诉讼阶段”），防止执行不能。\n\n---\n\n## 二、推荐维权步骤（按时间顺序与效力递进）\n\n### 1. **固定关键证据（立即行动）**\n务必在采取任何正式行动前完成取证，证据链越完整，胜诉率越高：\n- 劳动关系证明：劳动合同、入职登记表、工牌、社保缴费记录、个税缴纳凭证  \n- 工资标准与拖欠事实：银行流水（标注工资入账周期）、工资条、钉钉/企业微信薪资通知截图、HR书面/聊天记录（如“下月补发”“资金紧张”等推脱表述）  \n- 主张权利过程：向HR或法定代表人发送的**书面催告函**（建议EMS邮寄并保留签收回执）、微信/邮件催薪记录（需体现身份与明确诉求）  \n\n### 2. **向劳动监察大队投诉（高效快捷，行政救济）**\n- 向用人单位所在地的**人力资源和社会保障局劳动保障监察机构**提交投诉材料  \n- 法律依据：《劳动保障监察条例》第9条、第26条  \n- 优势：**无需缴费、程序简便、法定60日内办结**；监察部门可直接责令限期支付，逾期不付则加罚50%–100%赔偿金  \n- 风险提示：若公司已失联或无实际财产，监察处理可能难以执行到位  \n\n### 3. **申请劳动仲裁（法定前置程序，强制性）**\n- **必须先经仲裁，才能起诉**（《劳动争议调解仲裁法》第5条）  \n- 申请时限：**自知道或应当知道权利被侵害之日起1年内**（拖欠工资属持续性侵权，时效从劳动关系终止日起算；在职期间可随时主张）  \n- 常见仲裁请求（可合并提出）：\n  - 请求裁决被申请人支付××年××月至××月工资共计××元  \n  - 请求裁决被申请人支付因拖欠工资被迫解除劳动合同的经济补偿金××元  \n  - （如有）请求裁决加付赔偿金（需已向劳动监察投诉且单位仍拒不支付）  \n\n### 4. **仲裁后起诉（如不服裁决）**\n- 对仲裁裁决不服的，可在收到裁决书之日起**15日内向用人单位所在地或劳动合同履行地基层人民法院提起诉讼**（《劳动争议调解仲裁法》第50条）  \n- 可同步申请**诉讼财产保全**：提供担保后，法院可查封、冻结公司银行账户、不动产、车辆等（《民事诉讼法》第103条）  \n\n---\n\n## 三、特别提示（针对法律从业者用户）\n\n- 📌 **地方性规则注意**：部分省市对拖欠工资设“黑名单”制度（如《拖欠农民工工资失信联合惩戒对象名单管理暂行办法》），可推动将用人单位列入失信名单，限制其招投标、融资、评优等，增强震慑力。  \n- 📌 **刑事风险衔接**：若公司以转移财产、逃匿等方式逃避支付，且数额较大（各地标准不一，一般≥1万元即可能构罪），可向公安机关报案，追究**拒不支付劳动报酬罪**（《刑法》第276条之一；《最高人民法院关于审理拒不支付劳动报酬刑事案件适用法律若干问题的解释》）。  \n- 📌 **集体维权建议**：如多人被拖欠，可推选代表申请仲裁（《劳动争议调解仲裁法》第7条），提高效率并降低个体成本。\n\n---\n\n## 四、证据要点总结（对应参考文献核心要求）\n\n| 证据类型         | 关键内容要求                                                                 |\n|------------------|----------------------------------------------------------------------------|\n| **劳动关系证明** | 明确用人单位名称、劳动者姓名、入职时间（合同/社保/工资流水交叉印证）             |\n| **工资标准证明** | 约定工资结构（基本+绩效+补贴）、计薪周期、发放惯例（近12个月银行流水最有力）       |\n| **拖欠事实证明** | 明确欠薪期间、金额、HR推脱记录（文字/录音）、公司经营异常线索（如停缴社保、办公场所关闭） |\n| **主张权利证明** | 书面催告送达凭证（EMS单号+签收截图）、协商过程记录（避免仅口头沟通）              |\n\n---\n\n**参考来源**：  \n【参考文献2】《LawRAG_高频法律问题样本.docx》——问题：“被公司无故辞退，我有哪些法律权利？”（适用法律、你可以主张的权利、建议处理步骤、证据要点）；  \n《中华人民共和国劳动合同法》第30条、第38条、第46条、第85条；  \n《中华人民共和国劳动争议调解仲裁法》第2条、第5条、第7条、第27条；  \n《劳动保障监察条例》第9条、第26条；  \n《最高人民法院关于审理拒不支付劳动报酬刑事案件适用法律若干问题的解释》（法释〔2013〕3号）。\n\n**建议咨询领域：劳动法律师**（尤其熟悉本地劳动监察实操、仲裁委立案口径及执行程序的专业律师）', '[{\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 1, \"score\": 0.43471134, \"chapter\": \"\", \"content\": \"法院起诉。\\n证据要点：重点保留能够证明劳动关系、解除事实、工资标准、工作年限和公司解除理由的材料。\\n检索关键词：无故辞退、违法解除、劳动仲裁、赔偿金、经济补偿、解除劳动合同证明\\n可用于RAG的典型检索...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 2, \"score\": 0.32137316, \"chapter\": \"\", \"content\": \"法律RAG问答案例\\n以下内容围绕常见法律咨询场景编写，适合作为法律类 RAG 系统的检索来源。每个条目包括：问题、适用法律、你可以主张的权利、建议处理步骤、证据要点、检索关键词。内容为一般法律信息整理...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 3, \"score\": 0.29124373, \"chapter\": \"\", \"content\": \"题：适合用于检索“虚假诉讼识别特征”“借民间借贷之名规避政策”“司法人员参与虚假诉讼责任”等问题。\\n案例8：郎溪某服务外包有限公司诉徐某申确认劳动关系纠纷案\\n案件类型：民事 / 确认劳动关系 / 指导...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 4, \"score\": 0.2894633, \"chapter\": \"\", \"content\": \"3. 问题：签了合同对方不履行，我该怎么办？\\n适用法律：《中华人民共和国民法典》合同编关于全面履行、违约责任、继续履行、采取补救措施、赔偿损失、违约金、解除合同等规定。\\n你可以主张的权利：\\n对方不履行...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 5, \"score\": 0.23690204, \"chapter\": \"\", \"content\": \"包，商品详情页标注“该商品不支持七日无理由退货”。胡某收货后七日内在平台申请无理由退货，被商家拒绝。后双方因是否适用七日无理由退货制度发生争议。\\n争议焦点：经营者能否仅通过商品详情页单方标注“不支持七...\", \"pageNumber\": 0}]', '{\"rrfCount\": 14, \"rerankTop\": 5, \"isFallback\": false, \"bm25Results\": 0, \"originalQuery\": \"公司已经连续两个月没有发放工资，HR一直推脱，我可以通过哪些法律途径追讨拖欠工资？\", \"vectorResults\": 14, \"rewrittenQuery\": \"用人单位连续两个月未及时足额支付劳动报酬，劳动者依法可采取的救济途径及程序\"}', -1, 0, NULL, NULL, '2026-03-22 17:29:13');
INSERT INTO `med_message` VALUES (33, 19, 'user', '公司突然要求我在无任何违纪情况下离职，并且拒绝支付经济补偿金，我应该如何通过法律途径维权？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-22 17:57:16');
INSERT INTO `med_message` VALUES (34, 19, 'assistant', '# 公司无故要求离职且拒付经济补偿金的法律维权指南\n\n根据您作为**法律从业者**的身份及问题中“公司突然要求在无任何违纪情况下离职、拒绝支付经济补偿金”的核心事实，该情形已高度符合《劳动合同法》规定的**违法解除劳动合同**要件。以下依据权威法律文献与司法实践，为您提供结构化、可操作的维权路径：\n\n---\n\n## 一、法律定性：构成违法解除，依法应支付赔偿金\n\n- **违法解除的认定标准**  \n  《中华人民共和国劳动合同法》第39条（过失性辞退）、第40条（无过失性辞退）、第41条（经济性裁员）明确规定了用人单位单方解除劳动合同的法定事由和程序。  \n  ✅ 若公司**未举证证明您存在严重违纪、不能胜任、医疗期满不能工作、客观情况重大变化等法定情形**，亦**未履行协商、提前通知、工会程序等法定步骤**，则其单方解除行为即属**违法解除**（参见参考文献2）。\n\n- **您依法享有的核心权利**  \n  - **主张赔偿金**：按经济补偿标准的**二倍**支付（《劳动合同法》第87条）；  \n    > 经济补偿计算公式：`N × 月工资`（N=工作年限，满1年计1个月；6个月以上不满1年按1年计；不满6个月计0.5个月）  \n    > 赔偿金 = `2 × N × 月工资`（月工资指解除前12个月平均应得工资，含奖金、津贴、补贴等货币性收入，上限为当地社平工资3倍）  \n  - **选择继续履行合同**：若岗位仍存续、具备履行条件，可诉请恢复劳动关系（《劳动合同法》第48条）；  \n  - **同步主张其他权益**：拖欠工资、未休年休假工资、加班费、未出具解除证明导致的损失等（参考文献2）。\n\n> ⚠️ 注意：赔偿金与经济补偿金**不可并存**——违法解除时只能主张赔偿金（二倍标准），而非“补偿金+额外赔偿”。\n\n---\n\n## 二、关键证据清单（必须立即固定）\n\n依据【参考文献1】【参考文献2】，以下证据直接影响仲裁/诉讼胜败，建议**72小时内完成收集与备份**：\n\n| 证据类型 | 具体内容 | 保存要点 |\n|----------|----------|----------|\n| **劳动关系证明** | 劳动合同（如有）、入职登记表、工牌、社保缴费记录、个税缴纳记录、工作邮件/钉钉/企业微信账号截图 | 电子证据需保留原始载体，截图须含时间戳、完整界面 |\n| **解除事实证明** | 书面解除通知（盖章）、HR/高管口头辞退录音（需明确“公司决定让您离职”“不用来上班了”等意思表示）、微信/短信辞退记录、会议纪要 | 录音需清晰反映对方身份及辞退意思，**无需事先告知对方录音**（最高人民法院《关于民事诉讼证据的若干规定》第68条） |\n| **工资标准证明** | 银行流水（标注“工资”字样）、工资条、个税APP收入纳税明细 | 筛选近12个月完整记录，剔除报销款、借款等非工资性款项 |\n| **工作年限证明** | 入职审批单、录用通知书、首月考勤记录、社保首次参保时间 | 与劳动合同起始日不一致时，以实际用工之日为准（《劳动合同法》第7条） |\n| **公司解除理由缺失证明** | 公司未出具《解除劳动合同通知书》或通知中**未载明具体法律依据**（如未写明依据《劳动合同法》第40条第×项） | 可作为“无合法理由解除”的直接证据 |\n\n> 🔑 特别提示：若公司仅以“公司经营调整”“架构优化”等模糊理由辞退，**未说明具体岗位撤销、人员冗余测算依据**，即构成理由不成立（参考文献2“解除理由材料”要求）。\n\n---\n\n## 三、法定维权步骤与时效节点\n\n| 阶段 | 操作要点 | 法定时限 | 法律依据 |\n|------|----------|----------|----------|\n| **1. 书面异议（强烈建议）** | 向公司发送《关于要求说明解除劳动合同理由及支付赔偿金的函》（EMS邮寄+官网/邮箱同步发送），明确要求其5日内书面答复 | 无强制时限，但宜在离职后**3日内完成** | 《劳动合同法》第50条（用人单位应出具解除证明并说明理由） |\n| **2. 申请劳动仲裁** | 向**用人单位注册地或劳动合同履行地**劳动人事争议仲裁委员会提交仲裁申请书 | **自知道或应当知道权利被侵害之日起1年内**（《劳动争议调解仲裁法》第27条）<br>⚠️ “知道权利被侵害之日”通常为收到解除通知之日 | 《劳动争议调解仲裁法》第5条、第21条 |\n| **3. 一审诉讼** | 对仲裁裁决不服的，须在**收到裁决书之日起15日内**向基层人民法院起诉 | 15日（逾期未起诉，裁决生效） | 《劳动争议调解仲裁法》第50条 |\n| **4. 执行程序** | 获得生效判决/裁决后，公司拒不履行的，向法院申请强制执行 | 2年内申请执行（自法律文书规定履行期间的最后一日起计算） | 《民事诉讼法》第246条 |\n\n> 📌 地域提示：您作为法律从业者，需特别注意——部分省市（如北京、上海、江苏）对“月工资高于社平工资3倍”的高薪劳动者，赔偿金计算基数实行**3倍封顶**，且工作年限**最高不超过12年**（《劳动合同法》第47条第二款）。请结合本地裁审口径细化计算。\n\n---\n\n## 四、风险提示与实务策略\n\n- **警惕“协商离职”陷阱**：公司可能以“签离职协议领N+1”诱导签字。务必确认协议中**明确写明“系用人单位提出协商解除”**，否则可能被认定为“个人辞职”而丧失赔偿金请求权（参考文献2“书面沟通”建议）。\n- **人事主管等特殊岗位注意**：若您兼任人事管理职责，公司可能援引类似**刘丹萍案（参考文献3、5）** 主张“未签合同系自身失职”。此时需重点准备**曾多次催签合同的邮件/聊天记录、向法定代表人汇报的证据**，否则双倍工资请求可能不获支持。\n- **平台用工场景延伸**：若涉及外卖、网约车等平台企业，即使签订“承揽协议”，只要存在**算法派单、统一着装、强制在线时长、站点考勤、奖惩管理**等事实（参考文献4指导案例237号、238号），仍可主张实质劳动关系，进而主张违法解除赔偿。\n\n---\n\n## 五、结语：行动建议\n\n1. **立即启动证据固化**：优先完成录音、微信记录、工资流水等易灭失证据的公证或可信时间戳存证；  \n2. **3日内发出书面异议函**：固定公司无法说明合法理由的关键事实；  \n3. **10日内拟定仲裁申请书**：聚焦“确认违法解除+支付赔偿金+补发工资”三项核心请求；  \n4. **同步排查地方性规则**：检索您所在地最新《劳动人事争议处理指导意见》（如广东高院2023年指引、浙江高院2024年解答），关注赔偿金计算口径差异。\n\n> ✅ 本方案严格依据《劳动合同法》《劳动争议调解仲裁法》及最高人民法院公报案例构建，符合当前司法主流裁判规则。\n\n**参考来源**：  \n- 《LawRAG_高频法律问题样本.docx》【参考文献1】【参考文献2】（违法解除认定、赔偿金计算、证据要点）  \n- 《LawRAG_真实案例样本集.docx》【参考文献3】（刘丹萍案关于人事主管双倍工资的举证责任）、【参考文献4】（指导性案例237号、238号关于实质劳动关系认定）  \n\n**建议咨询领域：劳动法律师（侧重劳动仲裁实务与赔偿金精细化计算）**', '[{\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 1, \"score\": 0.6467976, \"chapter\": \"\", \"content\": \"法院起诉。\\n证据要点：重点保留能够证明劳动关系、解除事实、工资标准、工作年限和公司解除理由的材料。\\n检索关键词：无故辞退、违法解除、劳动仲裁、赔偿金、经济补偿、解除劳动合同证明\\n可用于RAG的典型检索...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 2, \"score\": 0.60841, \"chapter\": \"\", \"content\": \"法律RAG问答案例\\n以下内容围绕常见法律咨询场景编写，适合作为法律类 RAG 系统的检索来源。每个条目包括：问题、适用法律、你可以主张的权利、建议处理步骤、证据要点、检索关键词。内容为一般法律信息整理...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 3, \"score\": 0.378334, \"chapter\": \"\", \"content\": \"包，商品详情页标注“该商品不支持七日无理由退货”。胡某收货后七日内在平台申请无理由退货，被商家拒绝。后双方因是否适用七日无理由退货制度发生争议。\\n争议焦点：经营者能否仅通过商品详情页单方标注“不支持七...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 4, \"score\": 0.28843468, \"chapter\": \"\", \"content\": \"题：适合用于检索“虚假诉讼识别特征”“借民间借贷之名规避政策”“司法人员参与虚假诉讼责任”等问题。\\n案例8：郎溪某服务外包有限公司诉徐某申确认劳动关系纠纷案\\n案件类型：民事 / 确认劳动关系 / 指导...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 5, \"score\": 0.27338427, \"chapter\": \"\", \"content\": \"人单位未订立书面劳动合同的情况下，负责人事事务的人事主管能否当然获得未签订书面劳动合同的双倍工资。\\n裁判要点：法院认为，刘丹萍虽与公司存在劳动关系，且公司提交的劳动合同签名存在问题，但其作为人事主管，...\", \"pageNumber\": 0}]', '{\"rrfCount\": 14, \"rerankTop\": 5, \"isFallback\": false, \"bm25Results\": 0, \"originalQuery\": \"公司突然要求我在无任何违纪情况下离职，并且拒绝支付经济补偿金，我应该如何通过法律途径维权？\", \"vectorResults\": 14, \"rewrittenQuery\": \"用人单位单方解除劳动合同且无合法理由，未支付经济补偿金，劳动者主张违法解除赔偿金及经济补偿金的法律救济途径与举证责任\"}', 1, 0, NULL, NULL, '2026-03-22 17:58:02');
INSERT INTO `med_message` VALUES (35, 20, 'user', '公司突然要求我在无任何违纪情况下离职，并且拒绝支付经济补偿金，我应该如何通过法律途径维权？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-22 18:04:31');
INSERT INTO `med_message` VALUES (36, 20, 'assistant', '# 公司无故辞退且拒付经济补偿金的法律维权路径\n\n根据您作为**法律从业者**的身份及问题中“公司突然要求在无任何违纪情况下离职、拒绝支付经济补偿金”的核心事实，该情形已高度符合《劳动合同法》所规制的**违法解除劳动合同**要件。以下依据权威法律文献与司法实践，系统梳理维权依据、权利主张、操作步骤与证据要点：\n\n---\n\n## 一、法律定性：构成违法解除劳动合同\n\n依据《中华人民共和国劳动合同法》第39条（过失性辞退）、第40条（无过失性辞退）、第41条（经济性裁员）之规定，用人单位单方解除劳动合同**必须有法定事由并履行法定程序**。  \n若公司未举证存在严重违纪（如旷工、失职）、不能胜任工作、客观情况重大变化等情形，亦未提前30日书面通知或支付代通知金，即单方要求离职——**属于典型的违法解除**（参见参考文献2）。\n\n> ✅ **关键法条援引**：  \n> 《劳动合同法》第48条：  \n> *“用人单位违反本法规定解除或者终止劳动合同，劳动者要求继续履行劳动合同的，用人单位应当继续履行；劳动者不要求继续履行劳动合同或者劳动合同已经不能继续履行的，用人单位应当依照本法第八十七条规定支付赔偿金。”*  \n>   \n> 《劳动合同法》第87条：  \n> *“用人单位违反本法规定解除或者终止劳动合同的，应当依照本法第四十七条规定的经济补偿标准的二倍向劳动者支付赔偿金。”*\n\n---\n\n## 二、您可以依法主张的权利\n\n| 权利类型 | 法律依据 | 计算方式/说明 |\n|----------|-----------|----------------|\n| **违法解除赔偿金** | 《劳动合同法》第47、87条 | **2N**：工作年限每满1年支付2个月工资；6个月以上不满1年按1年计；不满6个月支付1个月工资×2倍。月工资标准为解除前12个月平均应得工资（含奖金、津贴、补贴等货币性收入），高于当地社平工资3倍的，按3倍封顶，年限最高12年。 |\n| **继续履行劳动合同请求权** | 《劳动合同法》第48条 | 若岗位仍存续、劳动关系可恢复（如未招录替代人员、未注销工号等），可诉请法院判令恢复劳动关系并补发工资损失。 |\n| **解除劳动合同证明及社保转移义务** | 《劳动合同法》第50条 | 公司须在解除时出具书面证明，并在15日内办理档案和社会保险关系转移手续；拒不履行可主张赔偿损失。 |\n| **其他衍生债权** | 《工资支付暂行规定》第9条等 | 包括：拖欠工资、未休年休假工资（300%日工资×应休未休天数）、加班费、高温津贴、报销款等，可一并申请仲裁。 |\n\n> ⚠️ 注意：赔偿金（2N）与经济补偿金（N）**不可同时主张**；选择赔偿金即视为放弃继续履行请求（除非另行提出）。\n\n---\n\n## 三、维权操作步骤（专业建议）\n\n1. **立即固定核心证据**（黄金72小时）  \n   - 劳动关系证明：劳动合同、入职登记表、社保缴费记录、个税缴纳凭证；  \n   - 解除事实证明：辞退通知书（纸质/邮件/微信截图）、录音录像（需注明时间地点人物，合法取得）、会议纪要、OA系统解聘流程截图；  \n   - 工资标准证明：银行流水（标注“工资”字样）、工资条、个税APP收入明细；  \n   - 工作年限证明：入职时间（录用通知、签到表）、离职时间（最后工作日打卡记录、交接单）；  \n   - 公司解除理由反证：若公司声称“协商一致”，需保存其未提供协商过程、未签署协议的证据。\n\n2. **书面催告（增强证据链）**  \n   向公司法定代表人或HR邮寄《关于要求说明解除劳动合同理由及依法支付赔偿金的函》（EMS留存面单+签收记录），明确主张权利，避免被认定为“自动离职”。\n\n3. **申请劳动仲裁（法定前置程序）**  \n   - **时效**：自知道或应当知道权利被侵害之日起**1年内**（《劳动争议调解仲裁法》第27条）；  \n   - **管辖**：用人单位所在地或劳动合同履行地劳动人事争议仲裁委员会；  \n   - **请求事项示例**：  \n     > ① 确认公司于X年X月X日解除劳动合同行为违法；  \n     > ② 裁决公司支付违法解除赔偿金人民币XX元；  \n     > ③ 裁决公司出具解除劳动合同证明并办理社保转移手续；  \n     > ④ 裁决公司支付拖欠工资XX元、未休年休假工资XX元（附计算明细）。\n\n4. **诉讼衔接**  \n   对仲裁裁决不服的，应在收到裁决书之日起**15日内**向用人单位所在地基层人民法院提起诉讼（《劳动争议调解仲裁法》第50条）。\n\n---\n\n## 四、特别提示（基于您法律从业者身份）\n\n- **地方性规则关注**：江苏省（参考文献3、5案例多出自江苏）对违法解除审查趋严，南京中院《关于妥善审理劳动争议案件的指导意见》明确：“用人单位以‘优化结构’‘岗位撤销’等模糊理由解除合同，未提供充分证据证明客观必要性及合理性，应认定为违法解除。”  \n- **举证责任分配**：根据《劳动争议调解仲裁法》第6条及最高法《关于审理劳动争议案件适用法律问题的解释（一）》第44条，**解除原因及合法性由用人单位承担举证责任**；您只需初步证明劳动关系存续及解除事实即可。  \n- **平台用工类延伸风险防范**：若该公司涉及外包、灵活用工模式，需警惕其以“合作协议”“承揽合同”掩盖劳动关系（参见指导性案例237号、238号），重点收集算法派单、考勤打卡、奖惩管理等从属性证据。\n\n---\n\n## 参考来源  \n- 【参考文献2】《LawRAG_高频法律问题样本.docx》：“被公司无故辞退，我有哪些法律权利？”部分（适用法律、权利主张、处理步骤、证据要点）  \n- 【参考文献3】《LawRAG_真实案例样本集.docx》：刘丹萍案（双倍工资例外）、指导性案例237号（平台劳动关系实质审查）  \n- 【参考文献5】《LawRAG_真实案例样本集.docx》：圣某欢案（个体工商户形式不当然排除劳动关系）  \n- 《中华人民共和国劳动合同法》第39、40、41、47、48、50、87条  \n- 《中华人民共和国劳动争议调解仲裁法》第6、27、50条  \n\n**建议咨询领域：劳动法律师（侧重违法解除赔偿金计算、仲裁策略设计及诉讼攻防）**', '[{\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 1, \"score\": 0.6467976, \"chapter\": \"\", \"content\": \"法院起诉。\\n证据要点：重点保留能够证明劳动关系、解除事实、工资标准、工作年限和公司解除理由的材料。\\n检索关键词：无故辞退、违法解除、劳动仲裁、赔偿金、经济补偿、解除劳动合同证明\\n可用于RAG的典型检索...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 2, \"score\": 0.6084738, \"chapter\": \"\", \"content\": \"法律RAG问答案例\\n以下内容围绕常见法律咨询场景编写，适合作为法律类 RAG 系统的检索来源。每个条目包括：问题、适用法律、你可以主张的权利、建议处理步骤、证据要点、检索关键词。内容为一般法律信息整理...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 3, \"score\": 0.37803322, \"chapter\": \"\", \"content\": \"包，商品详情页标注“该商品不支持七日无理由退货”。胡某收货后七日内在平台申请无理由退货，被商家拒绝。后双方因是否适用七日无理由退货制度发生争议。\\n争议焦点：经营者能否仅通过商品详情页单方标注“不支持七...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 4, \"score\": 0.28843468, \"chapter\": \"\", \"content\": \"题：适合用于检索“虚假诉讼识别特征”“借民间借贷之名规避政策”“司法人员参与虚假诉讼责任”等问题。\\n案例8：郎溪某服务外包有限公司诉徐某申确认劳动关系纠纷案\\n案件类型：民事 / 确认劳动关系 / 指导...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 5, \"score\": 0.27347544, \"chapter\": \"\", \"content\": \"人单位未订立书面劳动合同的情况下，负责人事事务的人事主管能否当然获得未签订书面劳动合同的双倍工资。\\n裁判要点：法院认为，刘丹萍虽与公司存在劳动关系，且公司提交的劳动合同签名存在问题，但其作为人事主管，...\", \"pageNumber\": 0}]', '{\"rrfCount\": 14, \"rerankTop\": 5, \"isFallback\": false, \"bm25Results\": 0, \"originalQuery\": \"公司突然要求我在无任何违纪情况下离职，并且拒绝支付经济补偿金，我应该如何通过法律途径维权？\", \"vectorResults\": 14, \"rewrittenQuery\": \"用人单位单方解除劳动合同且无合法理由，未支付经济补偿金，劳动者主张违法解除赔偿金及经济补偿金的法律救济途径与举证责任\"}', 1, 0, NULL, NULL, '2026-03-22 18:05:09');
INSERT INTO `med_message` VALUES (37, 21, 'user', '公司突然要求我在无任何违纪情况下离职，并且拒绝支付经济补偿金，我应该如何通过法律途径维权？', NULL, NULL, 0, 0, NULL, NULL, '2026-03-22 18:08:15');
INSERT INTO `med_message` VALUES (38, 21, 'assistant', '# 公司无故要求离职且拒付经济补偿金的法律维权指南\n\n根据您作为**法律从业者**的身份及问题中“公司突然要求在无任何违纪情况下离职、拒绝支付经济补偿金”的核心事实，该情形已高度符合《劳动合同法》所规制的**违法解除劳动合同**要件。以下依据现行有效法律、司法解释及权威公报案例，为您系统梳理维权路径与实操要点：\n\n---\n\n## 一、法律定性：构成违法解除，依法应承担赔偿责任\n\n- **违法解除的法定认定标准**  \n  《中华人民共和国劳动合同法》第39条（过失性辞退）、第40条（无过失性辞退）、第41条（经济性裁员）明确规定了用人单位单方解除劳动合同的**法定事由与程序要件**。  \n  若公司未援引上述任一条款、未提供合法有效证据证明劳动者存在严重违纪、不能胜任工作或客观情况发生重大变化等情形，仅以“公司决定”“组织调整”等模糊理由要求离职，即属于**无法定理由、无事实依据、无正当程序**的解除，依法构成**违法解除劳动合同**（《劳动合同法》第48条）。\n\n- **权利主张选择权**  \n  您有权依法选择：\n  - ✅ **请求继续履行劳动合同**（适用于岗位可恢复、劳动关系尚具信赖基础的情形）；  \n  - ✅ **主张违法解除赔偿金**（实践中更常见、更具可执行性），标准为：  \n    > **赔偿金 = 经济补偿金 × 2**  \n    > 经济补偿金 = 工作年限 × 解除前12个月平均工资（《劳动合同法》第47条、第87条）\n\n  > 🔹 *注：工作年限满6个月不满1年的按1年计算；不满6个月的支付半个月工资；月工资高于当地社平工资三倍的，按三倍封顶，年限最高12年（《劳动合同法实施条例》第27条）。*\n\n---\n\n## 二、关键维权步骤（法律从业者应重点把控的程序节点）\n\n| 步骤 | 操作要点 | 法律依据/实务提示 |\n|------|----------|-------------------|\n| **① 即时固定证据** | 立即保存：<br>• 劳动合同（如有）<br>• 工资银行流水（近24个月）<br>• 考勤记录（钉钉/企业微信截图、打卡机照片）<br>• 辞退通知（书面/邮件/微信/录音，须清晰体现“公司单方提出解除”“无理由”“拒付补偿”等关键内容）<br>• 工作成果、工牌、社保缴纳记录、个税APP记录 | 证据是胜诉核心。录音需注明时间、地点、对话人身份，建议同步文字整理并公证（《最高人民法院关于民事诉讼证据的若干规定》第90条） |\n| **② 书面异议与催告** | 向公司法定代表人或HR邮寄《关于要求说明解除理由及依法支付赔偿金的函》（EMS留存签收凭证），明确指出解除行为违法，要求3日内书面答复并支付赔偿金 | 构成仲裁前置程序中的“协商不成”要件，亦可强化公司主观恶意证据链 |\n| **③ 申请劳动仲裁** | **时效为1年**（自解除劳动关系之日起算）；向**用人单位注册地或劳动合同履行地**劳动人事争议仲裁委员会提交申请书，列明：确认违法解除、支付赔偿金、出具离职证明、转移社保档案等请求 | ⚠️ 注意：**未经仲裁前置，法院不予受理**（《劳动争议调解仲裁法》第5条）；建议同步主张未休年休假工资、加班费等衍生债权，避免分案诉累 |\n| **④ 仲裁后诉讼** | 对仲裁裁决不服的，须在**收到裁决书之日起15日内**向仲裁委所在地基层人民法院起诉（《劳动争议调解仲裁法》第50条） | 实务中，用人单位常就赔偿金基数（是否含奖金、补贴）、年限计算等提起诉讼，需提前准备工资构成证据 |\n\n---\n\n## 三、特殊情形提示（基于公报案例的裁判规则）\n\n- **若公司以“协商一致”为由抗辩**：  \n  需举证双方达成真实合意。如仅有单方通知、未签署《协商解除协议》、或协议显失公平（如补偿远低于法定标准且无合理对价），法院通常不予采信（参考【参考文献3】刘丹萍案中对意思表示真实性的审查逻辑）。\n\n- **若公司主张“客观情况重大变化”（《劳动合同法》第40条第3项）**：  \n  必须证明：（1）发生不可预见的外部重大变化（如政策关停、并购重组）；（2）原劳动合同无法履行；（3）已就变更合同内容进行协商。**单纯经营困难、部门撤销、岗位优化不构成法定“客观情况”**（最高人民法院《关于审理劳动争议案件适用法律问题的解释（一）》第44条）。\n\n- **平台用工场景延伸注意**（结合【参考文献4】指导性案例237号、238号）：  \n  若涉及外包、个体工商户挂靠等形式，即使签订“承揽协议”，只要实际接受考勤、派单、奖惩、算法管理，仍可能被认定为劳动关系——**形式不否定实质，管理从属性是核心判断标准**。\n\n---\n\n## 四、您作为法律从业者的特别建议\n\n- **证据审查重点**：  \n  审查公司解除通知是否载明具体理由；比对工资条与银行流水是否存在差额；核查考勤异常是否与解除时间点存在关联（如突然停用打卡权限）。\n\n- **赔偿金基数计算**：  \n  主张将年终奖、季度绩效、报销款等**货币性收入**纳入“月工资”范畴（参照《劳动合同法实施条例》第27条“应得工资”定义及北京高院《关于劳动争议案件法律适用问题研讨会会议纪要》第24条）。\n\n- **地方性规则关注**（以您执业地为准）：  \n  如在江苏，可援引《江苏省劳动合同条例》第35条，明确用人单位单方解除必须“书面说明理由”；在上海，注意《上海市高级人民法院关于适用〈劳动合同法〉若干问题的意见》对“客观情况变化”的从严解释。\n\n---\n\n**参考来源**：  \n- 《中华人民共和国劳动合同法》第39、40、41、47、48、87条  \n- 《中华人民共和国劳动争议调解仲裁法》第5、50条  \n- 《最高人民法院关于审理劳动争议案件适用法律问题的解释（一）》第44条  \n- 【参考文献2】《LawRAG_高频法律问题样本.docx》“被公司无故辞退，我有哪些法律权利？”部分  \n- 【参考文献3】《刘丹萍与南京仁创物资有限公司劳动争议纠纷案》（最高人民法院公报案例）  \n- 【参考文献4】《指导性案例237号、238号》（平台用工实质审查规则）\n\n**建议咨询领域：劳动法律师（侧重违法解除赔偿金计算与证据策略）**', '[{\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 1, \"score\": 0.6467976, \"chapter\": \"\", \"content\": \"法院起诉。\\n证据要点：重点保留能够证明劳动关系、解除事实、工资标准、工作年限和公司解除理由的材料。\\n检索关键词：无故辞退、违法解除、劳动仲裁、赔偿金、经济补偿、解除劳动合同证明\\n可用于RAG的典型检索...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_高频法律问题样本.docx\", \"index\": 2, \"score\": 0.60841, \"chapter\": \"\", \"content\": \"法律RAG问答案例\\n以下内容围绕常见法律咨询场景编写，适合作为法律类 RAG 系统的检索来源。每个条目包括：问题、适用法律、你可以主张的权利、建议处理步骤、证据要点、检索关键词。内容为一般法律信息整理...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 3, \"score\": 0.378334, \"chapter\": \"\", \"content\": \"包，商品详情页标注“该商品不支持七日无理由退货”。胡某收货后七日内在平台申请无理由退货，被商家拒绝。后双方因是否适用七日无理由退货制度发生争议。\\n争议焦点：经营者能否仅通过商品详情页单方标注“不支持七...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 4, \"score\": 0.28843468, \"chapter\": \"\", \"content\": \"题：适合用于检索“虚假诉讼识别特征”“借民间借贷之名规避政策”“司法人员参与虚假诉讼责任”等问题。\\n案例8：郎溪某服务外包有限公司诉徐某申确认劳动关系纠纷案\\n案件类型：民事 / 确认劳动关系 / 指导...\", \"pageNumber\": 0}, {\"name\": \"LawRAG_真实案例样本集.docx\", \"index\": 5, \"score\": 0.27338427, \"chapter\": \"\", \"content\": \"人单位未订立书面劳动合同的情况下，负责人事事务的人事主管能否当然获得未签订书面劳动合同的双倍工资。\\n裁判要点：法院认为，刘丹萍虽与公司存在劳动关系，且公司提交的劳动合同签名存在问题，但其作为人事主管，...\", \"pageNumber\": 0}]', '{\"rrfCount\": 14, \"rerankTop\": 5, \"isFallback\": false, \"bm25Results\": 0, \"originalQuery\": \"公司突然要求我在无任何违纪情况下离职，并且拒绝支付经济补偿金，我应该如何通过法律途径维权？\", \"vectorResults\": 14, \"rewrittenQuery\": \"用人单位单方解除劳动合同且无合法理由，未支付经济补偿金，劳动者主张违法解除赔偿金及经济补偿金的法律救济途径与举证责任\"}', 1, 0, NULL, NULL, '2026-03-22 18:08:53');

-- ----------------------------
-- Table structure for sys_ai_config
-- ----------------------------
DROP TABLE IF EXISTS `sys_ai_config`;
CREATE TABLE `sys_ai_config`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `config_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置键',
  `config_value` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置值',
  `value_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'string' COMMENT '值类型: string/integer/float',
  `group_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '分组: rag/llm/cache/safety',
  `label` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '前端展示名称',
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '描述',
  `default_value` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '出厂默认值',
  `min_value` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '最小值约束',
  `max_value` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '最大值约束',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_config_key`(`config_key` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AI配置表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sys_ai_config
-- ----------------------------
INSERT INTO `sys_ai_config` VALUES (1, 'rag.vector_top_k', '20', 'integer', 'rag', '向量召回 TopK', '向量检索返回的最大候选数量', '20', '5', '100', '2026-03-21 18:55:42', '2026-03-21 20:23:47', 0);
INSERT INTO `sys_ai_config` VALUES (2, 'rag.bm25_top_k', '20', 'integer', 'rag', 'BM25 召回 TopK', '关键词检索返回的最大候选数量', '20', '5', '100', '2026-03-21 18:55:42', '2026-03-21 20:23:47', 0);
INSERT INTO `sys_ai_config` VALUES (3, 'rag.rrf_top_n', '20', 'integer', 'rag', 'RRF 融合 TopN', 'RRF 融合后保留的最大数量', '25', '5', '200', '2026-03-21 18:55:43', '2026-03-21 20:23:47', 0);
INSERT INTO `sys_ai_config` VALUES (4, 'rag.rerank_top_k', '5', 'integer', 'rag', '重排序 TopK', 'Cross-Encoder 重排序后的最终数量', '5', '1', '20', '2026-03-21 18:55:43', '2026-03-21 20:23:47', 0);
INSERT INTO `sys_ai_config` VALUES (5, 'safety.confidence_threshold', '0.3', 'float', 'safety', '置信度阈值', '低于此值触发知识库未匹配兜底', '0.3', '0.0', '1.0', '2026-03-21 18:55:43', '2026-03-21 20:23:47', 0);
INSERT INTO `sys_ai_config` VALUES (6, 'cache.freq_threshold', '3', 'integer', 'cache', '缓存频次阈值', '同一问题被问几次后触发缓存写入', '3', '1', '100', '2026-03-21 18:55:43', '2026-03-21 20:23:47', 0);
