INSERT INTO `sys_ai_config` VALUES (8, 'llm.chat_temperature', '0.3', 'float', 'llm', '普通对话温度', '非流式对话（QueryRewriter/SafetyGuard）的采样温度', '0.3', '0.0', '1.0', '2026-03-21 19:09:44', '2026-03-21 19:09:44', 0);
INSERT INTO `sys_ai_config` VALUES (9, 'llm.streaming_temperature', '0.7', 'float', 'llm', '流式对话温度', '流式生成回答的采样温度，越高越发散', '0.7', '0.0', '1.0', '2026-03-21 19:09:44', '2026-03-21 19:09:44', 0);
INSERT INTO `sys_ai_config` VALUES (10, 'llm.timeout_seconds', '60', 'integer', 'llm', '超时时间(秒)', '单次 LLM 请求的最长等待时间（秒）', '60', '10', '300', '2026-03-21 19:09:44', '2026-03-21 19:09:44', 0);
INSERT INTO `sys_ai_config` VALUES (11, 'cache.ttl_hours', '24', 'integer', 'cache', '缓存有效时间(小时)', '高频问题缓存在 Redis 中的保留时长', '24', '1', '168', '2026-03-21 19:18:47', '2026-03-21 19:18:47', 0);
INSERT INTO `sys_ai_config` VALUES (12, 'rag.rrf_k_constant', '60', 'integer', 'rag', 'RRF 常数 K', 'RRF 公式经验常数，值越大头部优势越小', '60', '1', '200', '2026-03-21 21:20:06', '2026-03-21 21:20:06', 0);

-- ----------------------------
-- Table structure for sys_audit_log
-- ----------------------------
DROP TABLE IF EXISTS `sys_audit_log`;
CREATE TABLE `sys_audit_log`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint NULL DEFAULT NULL COMMENT '操作用户ID',
  `username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '操作用户名',
  `operation` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '操作描述',
  `method` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'HTTP方法: GET/POST/PUT/DELETE',
  `request_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '请求URL',
  `ip` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客户端IP',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '操作状态: 1成功 0失败',
  `create_time` datetime NOT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_username`(`username` ASC) USING BTREE,
  INDEX `idx_operation`(`operation`(64) ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 31 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '操作审计日志表' ROW_FORMAT = Dynamic;

