INSERT INTO `sys_notification` VALUES (4, 4, 'tets', '6666', 'system', 0, '2026-03-22 17:10:20');
INSERT INTO `sys_notification` VALUES (5, 1, '系统部署完成', 'LawRAG v2.0 已成功部署上线，新增消息通知、问题模板、操作审计日志、问答收藏夹等功能，欢迎体验！', 'system', 0, '2026-03-22 17:24:46');
INSERT INTO `sys_notification` VALUES (6, 1, '知识库更新提醒', '系统检测到知识库中有 3 篇文档处于处理失败状态，请及时前往知识库管理页面查看并重新处理。', 'system', 0, '2026-03-22 16:24:46');
INSERT INTO `sys_notification` VALUES (7, 1, '新用户注册通知', '过去 24 小时内有 2 位新用户完成注册，当前系统注册用户总数已达 4 人。', 'activity', 1, '2026-03-22 15:24:46');
INSERT INTO `sys_notification` VALUES (8, 1, '异常登录提醒', '检测到您的账户在非常用 IP 192.168.10.55 登录，登录时间今日 09:32，如非本人操作请及时修改密码。', 'security', 1, '2026-03-22 14:24:46');
INSERT INTO `sys_notification` VALUES (9, 1, 'AI 配置已更新', '管理员 admin 修改了 RAG 配置参数：向量检索 Top-K 调整为 25，重排序 Top-K 调整为 8，新配置已实时生效。', 'system', 1, '2026-03-21 17:24:46');
INSERT INTO `sys_notification` VALUES (10, 1, '问答满意度周报', '本周用户满意度为 87.5%，共收到有用反馈 42 次，无用反馈 6 次，较上周提升 5.2%。', 'activity', 1, '2026-03-20 17:24:46');
INSERT INTO `sys_notification` VALUES (11, 2, '欢迎加入 LawRAG', '您好！欢迎使用 LawRAG 智能法律咨询平台。您可以在智能问答中输入法律问题，系统将基于权威法律文献为您提供专业解答。', 'system', 0, '2026-03-22 17:24:46');
INSERT INTO `sys_notification` VALUES (12, 2, '新功能上线：问答收藏', '您现在可以在对话界面点击消息右下角的星形按钮收藏重要回答，收藏内容可在侧边栏我的收藏中随时查看。', 'activity', 0, '2026-03-22 16:54:46');
INSERT INTO `sys_notification` VALUES (13, 2, '密码安全提醒', '您的账户密码已超过 90 天未修改，为保障账户安全，建议您前往个人中心更新密码。', 'security', 1, '2026-03-17 17:24:46');
INSERT INTO `sys_notification` VALUES (14, 3, '欢迎加入 LawRAG', '您好！欢迎使用 LawRAG 智能法律咨询平台。您可以在智能问答中输入法律问题，系统将基于权威法律文献为您提供专业解答。', 'system', 0, '2026-03-22 17:24:46');
INSERT INTO `sys_notification` VALUES (15, 3, '新功能上线：快捷提问', '平台新增快捷提问模板功能，在对话页面点击输入框左侧的问号按钮，即可从模板库中快速选择常见法律问题进行咨询。', 'activity', 0, '2026-03-22 16:24:46');
INSERT INTO `sys_notification` VALUES (16, 3, '系统维护通知', '计划于本周六 00:00-02:00 进行系统维护升级，维护期间服务暂停，请提前做好安排，感谢您的理解与支持。', 'system', 1, '2026-03-19 17:24:46');
INSERT INTO `sys_notification` VALUES (17, 4, '欢迎加入 LawRAG', '您好！欢迎使用 LawRAG 智能法律咨询平台。系统已为您开通全功能权限，如有疑问请联系管理员。', 'system', 0, '2026-03-22 17:24:46');
INSERT INTO `sys_notification` VALUES (18, 4, '您的问题已收录为模板', '您近期咨询的劳动合同被违约怎么办已被管理员收录为快捷提问模板，感谢您对平台建设的贡献！', 'activity', 0, '2026-03-22 15:24:46');
INSERT INTO `sys_notification` VALUES (19, 4, '新功能上线：数据大屏', '管理后台数据大屏新增热门问题 TOP10 图表与满意度概览面板，欢迎管理员登录查看。', 'activity', 1, '2026-03-22 13:24:46');
INSERT INTO `sys_notification` VALUES (20, 4, '账户安全通知', '您已成功开启登录通知功能，每次登录时系统将发送安全提醒，如需关闭请前往个人中心设置。', 'security', 1, '2026-03-16 17:24:46');

-- ----------------------------
-- Table structure for sys_question_template
-- ----------------------------
DROP TABLE IF EXISTS `sys_question_template`;
CREATE TABLE `sys_question_template`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `title` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '模板标题',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '模板内容（完整问题文本）',
  `category` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'general' COMMENT '分类',
  `sort_order` int NOT NULL DEFAULT 0 COMMENT '排序序号，越小越靠前',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态: 1启用 0禁用',
  `create_time` datetime NOT NULL COMMENT '创建时间',
  `update_time` datetime NOT NULL COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除: 0正常 1已删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_sort_order`(`sort_order` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '问题模板表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_question_template
-- ----------------------------
INSERT INTO `sys_question_template` VALUES (1, '劳动合同被违约怎么办', '公司突然要求我在无任何违纪情况下离职，并且拒绝支付经济补偿金，我应该如何通过法律途径维权？', '劳动法', 1, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (2, '试用期被辞退有补偿吗', '我在试用期内被公司以\"不符合录用条件\"为由辞退，但公司没有明确告知过录用条件，我能获得赔偿吗？', '劳动法', 2, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (3, '工资被拖欠怎么维权', '公司已经连续两个月没有发放工资，HR一直推脱，我可以通过哪些法律途径追讨拖欠工资？', '劳动法', 3, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (4, '婚前财产离婚怎么分', '婚前我个人购买的房产，结婚后用共同积蓄还贷，离婚时这套房产应该如何分割？', '婚姻家庭', 4, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (5, '离婚后孩子抚养权归谁', '我和配偶协议离婚，孩子3岁，我们双方都想要抚养权，法院一般会如何判决？', '婚姻家庭', 5, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (6, '合同违约如何索赔', '我与供应商签订了采购合同，对方逾期交货导致我损失了客户订单，我可以要求哪些赔偿？', '合同法', 6, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (7, '电商购物遭遇假货维权', '在某电商平台购买了一件商品，收到后确认是假冒伪劣产品，我可以要求退款并索赔吗？', '消费者权益', 7, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (8, '房东不退押金怎么办', '租房合同到期，我按时搬离且房屋没有损坏，但房东以各种理由拒绝退还押金，我该如何处理？', '合同法', 8, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (9, '遭遇网络诈骗如何报案', '我被网络诈骗损失了2万元，已经掌握了对方的账号和转账记录，应该向哪个部门报案，能追回来吗？', '刑法', 9, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (10, '交通事故对方不赔怎么办', '我被对方车辆追尾，对方全责，但保险公司迟迟不赔付，我应该怎么处理？', '民法', 1, 1, '2026-03-22 17:08:36', '2026-03-22 17:16:11', 0);
INSERT INTO `sys_question_template` VALUES (11, '个人信息被泄露如何维权', '我发现某公司将我的个人信息出售给第三方，导致我频繁接到骚扰电话，我有哪些法律救济途径？', '个人信息保护', 11, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);
INSERT INTO `sys_question_template` VALUES (12, '房屋买卖合同纠纷', '我已支付购房定金，但卖方反悔不想卖了，我是否可以要求双倍返还定金？', '合同法', 12, 1, '2026-03-22 17:08:36', '2026-03-22 17:08:36', 0);

-- ----------------------------
-- Table structure for sys_user
-- ----------------------------
DROP TABLE IF EXISTS `sys_user`;
CREATE TABLE `sys_user`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户名',
  `password` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '密码(BCrypt加密)',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '手机号',
  `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '昵称',
  `avatar` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '头像URL',
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'user' COMMENT '角色: admin/user',
  `legal_profile` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '法律档案 JSON',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态: 1正常 0禁用',
  `last_login` datetime NULL DEFAULT NULL COMMENT '最后登录时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_username`(`username` ASC) USING BTREE,
  INDEX `idx_phone`(`phone` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统用户表' ROW_FORMAT = DYNAMIC;

